e":"良好","level":4},{"icon":"footprints","label":"步行","value":"适中","level":3},{"icon":"cloud-rain","label":"雨天安全","value":"良好","level":4},{"icon":"users","label":"适合家庭","value":"良好","level":4},{"icon":"gauge","label":"平衡","value":"均衡","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原华城","alt":"水原华城 — 图库图片 1","caption":"水原华城 — 照片 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield 水原图书馆与购物中心","alt":"Starfield 水原图书馆与购物中心 — gallery image 1","caption":"Starfield 水原图书馆与购物中心 — photo 1"},{"id":3,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","location":"卧牛精舍","alt":"卧牛精舍 — gallery image 1","caption":"卧牛精舍 — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原华城","alt":"水原华城 — 图库图片 2","caption":"水原华城 — 照片 2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原华城","alt":"水原华城 — 图库图片 3","caption":"水原华城 — 照片 3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原华城","alt":"水原华城 — 图库图片 4","caption":"水原华城 — 照片 4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原华城","alt":"水原华城 — 图库图片 5","caption":"水原华城 — 照片 5"},{"id":8,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield 水原图书馆与购物中心","alt":"Starfield 水原图书馆与购物中心 — gallery image 2","caption":"Starfield 水原图书馆与购物中心 — photo 2"},{"id":9,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield 水原图书馆与购物中心","alt":"Starfield 水原图书馆与购物中心 — gallery image 3","caption":"Starfield 水原图书馆与购物中心 — photo 3"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield 水原图书馆与购物中心","alt":"Starfield 水原图书馆与购物中心 — gallery image 4","caption":"Starfield 水原图书馆与购物中心 — photo 4"},{"id":11,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","location":"卧牛精舍","alt":"卧牛精舍 — gallery image 2","caption":"卧牛精舍 — photo 2"},{"id":12,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","location":"卧牛精舍","alt":"卧牛精舍 — gallery image 3","caption":"卧牛精舍 — photo 3"},{"id":13,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","location":"卧牛精舍","alt":"卧牛精舍 — gallery image 4","caption":"卧牛精舍 — photo 4"},{"id":14,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","location":"卧牛精舍","alt":"卧牛精舍 — gallery image 5","caption":"卧牛精舍 — photo 5"}],"itineraryStops":[{"number":1,"time":"≈ 10:00","duration":"75 分钟","name":"水原华城","category":"联合国教科文组织世界遗产城堡","description":"**水原华城（수원화성）——1997年列入联合国教科文组织世界遗产** — 是韩国唯一一座保存有原始10册建造档案的城墙古城（《华城城役仪轨》，于2007年单独列入联合国教科文组织世界记忆名录）。华城由正祖大王（정조，朝鲜第22代君主，在位\n\n1776-1800年）主持，**仅用2年9个月（1794-1796年）**建造完成，是正祖将朝鲜王朝都城从汉阳（首尔）迁至水原计划的一部分——同时也是为了纪念其父思悼世子。思悼世子于1762年被其父英祖大王活活封入米柜而死。\n\n华城由**丁若镛（정약용，又名茶山）**设计——朝鲜王朝实学（实用主义学派）的杰出学者兼工程师——他将韩国传统防御建筑与中国攻城防御理论以及新兴西方筑城科学融为一体。\n\n丁若镛发明了**举重机（거중기）**——一种基于西方机械原理的滑轮组起重机——用于施工中吊运重石；这是西式现代工程学首次有据可查地应用于韩国建筑。\n\n完整城墙**周长5.74公里**，围合130公顷土地，设有41处战略建筑：4座主门（长安门居北——**韩国现存最大的王室城门**，规模超过首尔崇礼门；八达门居南；华西门居西；苍龙门居东）、4座角楼、4处指挥所、5处哨望台、5处炮台，另有射箭台、水门及烽火台等。\n\n今日导览步行路线覆盖**长安门（北主门）至华西门（西门，国宝第403号）之间最具拍照价值的1.2公里路段**——保存完好的军事建筑密度最高，步行约25-30分钟。还可登上八达山顶的**西将台（西指挥所）**，欣赏华城最高视角，感受昔日国王的战略指挥位置。\n\n**华虹门（北水门）**横跨水原川，7拱飞架，是华城被拍摄最多的建筑——尤以春季（樱花盛开）和秋季（层林尽染）为甚。旅游团徒步游览城墙；如行程允许，还可选乘**华城观光小火车**（成人4,000韩元，约30分钟，练武台→八达门路线）。","highlights":["**1997年列入联合国教科文组织世界遗产** — 韩国唯一保存有原始建造记录的城墙古城","1794-1796年建造，历时2年9个月，由正祖大王（朝鲜第22代君主）主持","由丁若镛运用韩国、中国及西方筑城学融合设计","《华城城役仪轨》建造档案 — 2007年列入联合国教科文组织世界记忆名录","城墙周长5.74公里，设有41处军事战略建筑","长安门北门 — **韩国现存最大的王室城门**","长安门 → 华西门 1.2 公里导览步行（拍照密度最高路段）","华虹门七拱水门 — 拍照最多的标志性建筑","免费入场：穿韩服者 + 每月最后一个周三 + 65 岁以上老人"],"timeUsed":["在长安门附近下车（约 5 分钟）","在长安门进行简短团队说明（约 5 分钟）","经华西将阁步行长安门 → 华西门（约 25-30 分钟）","拍照时间 + 返回车辆集合（约 10 分钟）","可选：华城列车观光小火车 练武台↔八达门（单程约 30 分钟；成人 ₩4,000）"],"whyOnRoute":"本线路的联合国教科文组织世界遗产核心景点——韩国唯一现存的城墙围城，建于 1794-1796 年正祖王时期。长安门 → 华西门步行路段（约 1.2 公里），在 75 分钟停留时间内汇聚了密度最高的军事建筑遗址，以及标志性的华虹门七拱水门。相比全程 5.74 公里环线，选择此路段是因为它涵盖了拍照最多、历史最为丰富的区域，同时为当天其他三处遗产景点保留了充足时间。华城也是**水原一日游的必游核心**，因为它将行宫宫殿完全包围在内——这意味着上午的水原游览便可体验联合国教科文组织世界遗产与朝鲜王朝皇家宫殿内部，随后行程继续前往星空图书馆与卧牛精舍。经华西将阁的长安门 → 华西门 1.2 公里城墙段，是韩国军事建筑保存密度最高的路段（4 座主城门 + 5 座暗门 + 4 处水门 + 거중기（传统起重装置）修建的城垛，均在 25-30 分钟步行范围内共存）。","visitBasics":{"hours":"城墙步道全天 24 小时开放（无城门限制）；建议游览时间：夏季 09:00-18:00 / 冬季 09:00-17:00；5 月至 10 月夜间开放时间：周三至周日 18:00-21:30","closed":"全年开放（华城列车周一休息）","admission":"成人 1,000 / 青少年 700 / 儿童 500 韩元（免费：6 岁以下儿童、65 岁以上老人、穿韩服者、每月最后一个周三）。华城列车另收 4,000 韩元","walking":"中等难度——城墙在西将台附近有较陡路段；城门处有台阶；部分路段轮椅通行困难"},"convenience":{"restroom":"设于长安门、华西门、八达门及练武台","parking":"大巴在长安门停车场下客；练武台设有专用大巴停车区"},"smartNotes":{"photo":"**华虹门（北水门）** 七拱横跨水原川——标志性拍摄地，春季（樱花盛开）和秋季（层林尽染）尤为迷人。**长安门（韩国现存最大的王室城门）** 黄金时段光线绝佳。**西将台（西部指挥所）** 可俯瞰八达山日落美景。","facilities":"游客服务中心位于长安门、八达门及华城行宫广场。全程设有英韩双语标识。华城语音导览可在长安门处租借。","tip":"请穿舒适的鞋子——城墙石面凹凸不平。行宫广场的韩服租赁店可享城堡及宫殿**免费**入场。**除非预留 2.5 小时以上，否则建议避免完整的 5.74 公里环线**——长安门 → 华西门路段每米遗产密度最高。"},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","KoreaToDo","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原华城","caption":"水原华城 — 照片 1","alt":"水原华城 — 图库图片 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原华城","caption":"水原华城 — 照片 2","alt":"水原华城 — 图库图片 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原华城","caption":"水原华城 — 照片 3","alt":"水原华城 — 图库图片 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原华城","caption":"水原华城 — 照片 4","alt":"水原华城 — 图库图片 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原华城","caption":"水原华城 — 照片 5","alt":"水原华城 — 图库图片 5"}]},{"number":2,"time":"≈ 11:30","duration":"75 分钟","name":"华城行宫","category":"朝鲜王朝行宫","description":"**华城行宫（화성행궁）——韩国现存最大的行宫（离宫）** — 建于1789至1796年，由正祖大王主持修建，是华城要塞城市统一规划的一部分。\n\n**行宫**是朝鲜时代国王出行、避难或举行特殊典礼时使用的临时王室居所；华城行宫的规模超过温阳、北汉山和南汉山行宫。正祖大王修建华城行宫的主要目的，是前往祭拜其被处决的父亲思悼世子的陵墓（显隆园，现称融陵，位于南方约4公里处）时留宿 — 他在位期间共进行了**13次**谒陵之行。\n\n其中最著名的是**1795年的王室巡幸**，随行人员多达6,000人，马匹1,400匹，此次巡幸是为庆祝惠庆宫洪氏（国王生母、思悼世子遗孀）六十大寿而举行。\n\n1795年的巡幸活动记录于**《园幸乙卯整理仪轨》——该文献自2007年起被列入联合国教科文组织世界记忆名录**。行宫最初由**576间（房间/结构单元）**构成，是一座功能完备的微型王室宫殿，设有正殿（奉寿堂）、次殿（洛南轩）、寝殿（长安轩）、御厨、军事衙门及卫兵营房。\n\n**在日本殖民统治时期**（1910-1945年），行宫遭到大规模破坏，日方将宫殿旧址改建为水原道立医院和警察署。\n\n**复原工作于1996年启动**，依据原始《华城城役仪轨》建设记录进行；第一期工程于2003年竣工（奉寿堂、洛南轩、长安轩、维与宅），第二期工程于2009年竣工（右华馆御厨、新丰楼入口大门）。复原工作至今仍在持续。\n\n**重要历史说明：洛南轩（낙남헌）是唯一一栋保存至今的1796年原始建筑** — 日方将其改作警察署办公用途，但未予拆除。因此，它是该遗址上唯一真实的原始木构建筑，其余建筑均为后期重建。\n\n**每日王室换岗仪式**在新丰楼大门举行 — **周二至周日上午11时**（视天气情况而定），约15分钟，**免费**。仪式重现朝鲜时代的宫门换岗典礼，卫兵身着红、蓝、黄色传统服装，配以传统鼓乐和号角。\n\n行程在条件允许的情况下，以赶上上午11时仪式为目标。此处曾作为韩剧**《大长今》（2003年）**的拍摄地 — 这部具有代表性的朝鲜时代史剧在 MBC 创下约57%的最高收视率 — 使其成为韩国史剧拍摄最频繁的取景地之一。","highlights":["**韩国现存最大的行宫（离宫）** — 最初共576间房","由正祖大王主持，与华城要塞同期建于1789至1796年","正祖大王曾13次亲临此地，祭拜其被处决的父亲思悼世子","**洛南轩 = 唯一保存至今的1796年原始建筑**（其余均为重建）","**王室换岗仪式，周二至周日上午11时，新丰楼大门（免费，约15分钟）**","1795年王室巡幸活动已被列入联合国教科文组织世界记忆名录","韩剧《大长今》（2003年 MBC，最高收视率约57%）的拍摄地","身穿韩服者、65岁及以上老人、6岁及以下儿童**免费**入场","**洛南轩（낙남헌）是1796年原始建筑中唯一留存至今的建筑** — 日本殖民时期当局将其改建为警察署办公室，但并未将其拆除；如今行宫内可见的其他所有建筑均为1996年后依据《华城城役仪轨》（2007年列入联合国教科文组织世界记忆名录）重建而成"],"timeUsed":["距华城城墙（华西门区域）步行约5分钟","提前抵达，观看新丰楼**11:00 王室卫兵换岗仪式**（约15分钟）","奉寿堂正殿 + 洛南轩 + 长安轩参观游览（约30分钟）","拍照留念 + 返回车辆集合（约15分钟）","可选：新丰楼城门王室卫兵换岗仪式（周二至周日上午11:00，约15分钟，免费 — 视天气情况而定）"],"whyOnRoute":"与城墙游览相得益彰——这处临时王室行宫位于同一联合国教科文组织遗址内，相距仅5分钟路程。这里是韩国最大的行宫（原有576间房），其中**洛南轩是唯一保存至今的原始建筑**（其余建筑均为1996年后依据《华城仪轨》重建）。建议合理安排到达时间，以赶上王室卫兵换岗仪式（周二至周日上午11:00），该仪式免费参观，历时约15分钟，是行程中难得的免费文化体验亮点。在参观城墙之后游览行宫，可将抽象的军事建筑认知转化为真实的朝鲜王朝皇家空间体验——同一座奉寿堂正殿，既是1795年正祖大王接见官员之地，也曾举办为其母惠庆宫洪氏庆贺60大寿的盛大宴会（场景记录于保存在仪轨中的班次图宫廷画卷中）。**城墙+行宫联票**售价3,500韩元（单独购票合计2,500韩元），是水原行程中具有实际附加价值的优惠选择。新丰楼城门王室卫兵换岗仪式（周二至周日上午11:00，约15分钟，免费）的时间安排与大多数从首尔出发当日往返游客抵达水原的时间相吻合。","visitBasics":{"hours":"09:00-18:00（最后入场时间17:30）；夏季（5月-10月）夜间开放时间18:00-21:00","closed":"全年开放","admission":"成人1,500 / 青少年1,000 / 儿童700韩元。城墙+行宫联票3,500韩元。身穿韩服者、65岁及以上老人、6岁及以下儿童免费","walking":"轻松无障碍 — 宫殿地面大部分平坦，各庭院之间有少量台阶"},"convenience":{"restroom":"设于正门入口、奉寿堂附近及行宫广场","parking":"华城行宫公共停车场；行宫广场收费停车场"},"smartNotes":{"photo":"**奉寿堂正殿** — 标志性正殿拍摄地。**洛南轩** — 唯一的1796年原始建筑（历史感最强的拍摄地）。**新丰楼城门王室卫兵换岗仪式**（周二至周日上午11:00）。身着韩服在新丰楼前留影 — 水原最受欢迎的韩服拍照地。","facilities":"游客信息中心、洗手间、礼品店。行宫广场设有咖啡厅及韩服租赁服务（4小时15,000-20,000韩元）。水原통닭（整只炸鸡）餐厅步行5分钟可达。","tip":"**合理安排到达时间，观看周二至周日上午11:00的王室卫兵换岗仪式（免费）**。租借韩服可同时免费进入城墙与行宫两处景点。**洛南轩是历史意义最为重大的单一景点** — 唯一未经重建、在日本殖民时期拆除中幸存下来的建筑。避免周一前往 — 王室卫兵换岗仪式仅在周二至周日举行。"},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原华城","caption":"水原华城 — 照片 1","alt":"水原华城 — 图库图片"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原华城","caption":"水原华城 — 照片 2","alt":"水原华城 — 图库图片"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原华城","caption":"水原华城 — 照片 3","alt":"水原华城 — 图库图片"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原华城","caption":"水原华城 — 照片 4","alt":"水原华城 — 图库图片"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原华城","caption":"水原华城 — 照片 5","alt":"水原华城 — 图库图片"}]},{"number":3,"time":"≈ 13:30","duration":"90 分钟","name":"Starfield 水原图书馆与购物中心","category":"现代文化地标 + 午餐","description":"**Starfield 图书馆水原（별마당 도서관 수원）** — 位于 **Starfield 水原购物中心，新世界地产旗下\"第二代\"Starfield 旗舰购物中心，于 2024 年 1 月 26 日正式开业**，是新世界地产旗下第五座 Starfield 购物中心；总投资超过 1 万亿韩元（约 7.5 亿美元）；建筑总面积约 334,000 平方米，是继 Starfield 河南之后韩国第二大室内购物中心。\n\n图书馆由 **BCHO Partners（赵秉洙）** 联合设计——该韩国建筑事务所曾主导原 COEX Starfield 图书馆（2017 年）的设计——水原图书馆是第二代版本，**书架高达 22 米**，是韩国任何公共空间中最高的圆柱形书架结构之一。\n\n图书馆横跨 **4 个楼层（1 楼至 4 楼中庭通廊）**，馆藏约 **70,000 册书籍与杂志**，涵盖韩国及国际出版物、期刊、艺术书籍，以及 4 楼专设的儿童文学区。\n\n**免费向公众开放** — 无需借书证，无需门票，购物中心营业期间均可入内。特色亮点：**黑胶唱片聆听休息室**，精选韩国独立音乐及爵士/经典摇滚黑胶唱片；中庭设有**每月轮换艺术展览**；以及**中庭春季樱花装置（3 月至 4 月）**，数千朵粉色 LED 花瓣盛放 — 是水原最受欢迎的春日拍照胜地之一。\n\n**本次 90 分钟停留含午餐**，地点为 **Eatopia 美食广场（B1 层）**，汇聚 30 余家餐厅，从快餐韩式料理（5,000–10,000 韩元）到中档韩式及国际料理（15,000–25,000 韩元）应有尽有。韩国烤肉、拌饭、刀切面、韩式饺子、日式猪排、韩墨融合料理（Ko-Mex）、Mountain Bus 澳式汉堡、越南河粉、蒸饺 — 菜系丰富多样。\n\n购物中心周边配套：**Aquafield 水原水上乐园 + 韩式汗蒸幕（B1–2 层）** 另需门票约 25,000–35,000 韩元；**玩具王国（4 楼，韩国最大玩具店）**；**CGV/MEGABOX 双影院组合**。\n\n**Starfield 免费接驳巴士**从水原站 4 号出口出发，每 10–15 分钟一班（车程约 10 分钟）— 是乘坐公共交通最便捷的抵达方式。年访客量：**首年（2024 年）约 2,800 万人次** — 位列韩国访客量最多的购物目的地前三名。","highlights":["**新世界旗下第二代 Starfield 旗舰购物中心 — 2024 年 1 月 26 日开业**","由BCHO Partners设计（该事务所亦于2017年设计了原COEX星空图书馆）","**4层图书馆，配备22米高书架** — 韩国最高圆柱形书架之一","约70,000册图书及杂志，免费开放","黑胶唱片试听休息室","樱花LED花瓣装置艺术（3月至4月）","**午餐含于本站行程** — Eatopia美食广场位于B1F，逾30家餐厅","Aquafield水上乐园及韩式温泉水疗、玩具王国（韩国最大）、CGV+MEGABOX影院","从水原站4号出口乘坐Starfield免费接驳巴士（约10分钟）","开业首年（2024年）访客约2,800万人次"],"timeUsed":["从水原华城乘坐大巴至Starfield水原，车程约30分钟","在Eatopia美食广场用午餐（约30至45分钟）","图书馆及中庭漫步与拍照时间（约30至40分钟）","简短购物浏览及在大巴处集合（约10至15分钟）","可选Eatopia美食广场午餐（B1F，30余家韩式及国际餐厅；人均约₩10,000–25,000；45至60分钟）"],"whyOnRoute":"这是上午UNESCO世界遗产压轴景点之后的\"现代韩国\"平衡点。**图书馆与午餐组合停靠**是3号行程的设计核心——充分利用Eatopia美食广场解决午餐问题（省去单独的餐厅停靠环节）。图书馆与22米高书架是建筑精华所在，全室内环境可有效规避正午天气风险。**午餐就在Starfield的Eatopia美食广场解决** — 90分钟的组合停靠自然融入紧凑的四站行程安排。作为正午过渡站点，Starfield图书馆在水原华城厚重的历史建筑内容与臥牛精舍复杂的宗教融合内容之间，发挥着**建筑与休闲缓冲区**的作用——22米中庭书架以**免费入场**带来打卡拍照的满足感，而周边商场（600余个零售品牌、Eatopia美食广场、Aquafield水上乐园）则提供灵活的午餐＋洗手间＋咖啡＋购物暂停综合配套服务，这是水原华城和臥牛精舍均无法直接提供的。","visitBasics":{"hours":"商场营业时间10:00–22:00；图书馆在商场营业期间全程开放","closed":"每月休馆1至2天（通常为周一——请提前网上确认）","admission":"图书馆免费；Eatopia美食广场按消费结算（午餐人均约5,000–25,000韩元）","walking":"无障碍出行便利——各楼层均设自动扶梯与电梯；全程支持轮椅及婴儿车通行"},"convenience":{"restroom":"每层均设多处洗手间；配有家庭友好型设施","parking":"地下停车场约5,000个停车位；在商场消费满30,000韩元可享前3小时免费停车；设有团体大巴专属停车区"},"smartNotes":{"photo":"**图书馆中央中庭22米高书架** — 从4楼展廊俯瞰全景。**黑胶唱片休息室**营造复古美感。**中庭樱花装置（3月至4月）** — 爆款季节性打卡照。圣诞树（12月）。4楼儿童区适合家庭合影留念。","facilities":"Eatopia美食广场B1F（30余家餐厅，消费5,000–40,000韩元），玩具王国4F，Aquafield水上乐园B1–2F，CGV＋MEGABOX影院，免费WiFi，多语种客户服务，主要商店设退税柜台。","tip":"**图书馆在商场营业期间全程免费开放**。**22米高书架 = 韩国最高图书馆书架**（告知游客以增强印象）。**3月至4月樱花装置**是季节性必看亮点。**Eatopia美食广场午餐** — 无需预订；建议13:00–13:30前往以避开韩国午餐高峰期。避免周六下午（人流高峰）。出发前请网上确认Starfield每月休馆日期。"},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["Starfield official","VisitKorea","Shinsegae press","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield 水原图书馆与购物中心","caption":"Starfield 水原图书馆与购物中心 — photo 1","alt":"Starfield 水原图书馆与购物中心 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield 水原图书馆与购物中心","caption":"Starfield 水原图书馆与购物中心 — photo 2","alt":"Starfield 水原图书馆与购物中心 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield 水原图书馆与购物中心","caption":"Starfield 水原图书馆与购物中心 — photo 3","alt":"Starfield 水原图书馆与购物中心 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield 水原图书馆与购物中心","caption":"Starfield 水原图书馆与购物中心 — photo 4","alt":"Starfield 水原图书馆与购物中心 — gallery image 4"}]},{"number":4,"time":"≈ 15:30","duration":"75 分钟","name":"卧牛精舍","category":"佛教寺庙（现代折衷风格）","description":"**卧牛精舍（와우정사）** — **由金海根（김해근）僧人于1970年创建**，作为因朝鲜战争（1950-1953年）半岛分裂而与故乡寺庙离散的朝鲜佛教僧侣的避难所。\n\n该寺庙最初以\"千一佛\"（字面意思为\"千零一佛之寺\"）命名，以向33位佛教神明致敬，并融入了韩国统一祈祷的深远意涵。\n\n**卧牛（와우, 臥牛）** = \"卧牛\" — 源于附近莲花山（Yeonhwasan）的地形，从远处望去形似一头静卧的牛。\n\n**精舍（정사, 精舍）** = \"寺庙\"（佛教精舍）。因此，全名译为\"卧牛寺\"。**韩国建筑风格最为独特的佛教寺庙之一** — 折衷融合设计，汇聚了印度、斯里兰卡、泰国、缅甸（Burma）、西藏、中国及韩国各地佛教传统的精华元素。\n\n寺内陈列着约3,000尊来自亚洲各佛教国家的佛像。**这并非典型的朝鲜王朝时期韩国寺庙**，而是一座建于1970年的统一祈祷寺庙 — 请向游客特别说明此区别。标志性景观包括：由单棵印度尼西亚刺柏木整木雕刻而成的**12米长、3米高木雕卧佛（卧佛／와불）** — **世界上最大的木雕卧佛**（吉尼斯世界纪录）；位于寺庙入口处、以青铜铸造并覆有金箔涂层的**8米室外佛头雕塑（佛头, 불두）**，是韩国最高的佛头雕塑之一；由从缅甸进口的白玉雕刻而成的**3米坐姿玉佛** — 韩国最大的玉佛；以及**梵帝殿主殿**，内供一尊从缅甸进口的8米铜佛。\n\n**统一大钟（통일대종）** — 1988年汉城奥运会开幕时敲响的12吨青铜大钟，为祈愿韩国统一而铸造；游客可敲响此钟（欢迎随喜捐款）。\n\n**因陀罗跋那塔（인드라바르나탑）** 采用斯里兰卡风格，外覆白色灰泥。**塔内供奉着由斯里兰卡、泰国及缅甸佛教协会赠予的佛陀舍利** — 这是一份独一无二的佛教外交礼物。\n\n**免费入场**。提供**寺庙住宿体验（Templestay）**（过夜僧侣带领修行、传统108拜礼、禅修冥想、佛教寺庙素斋、传统茶道 — 可通过templestay.com预订，每晚约70,000-90,000韩元）。\n\n**最佳摄影季节：春季樱花盛开（4月）与秋季红叶（10-11月）** — 金黄银杏与火红枫叶将寺庙建筑衬托得美不胜收。\n\n寺庙庭院坐落于山坡之上，各殿堂之间以台阶相连；步行约500米，需爬升一定高度。","highlights":["**由金海根（김해근）僧人于1970年创建，作为韩国统一祈祷寺庙**","折衷融合设计 — 泛亚佛教风格（印度、斯里兰卡、泰国、缅甸、西藏、中国、韩国）","约3,000尊来自亚洲各佛教国家的佛像","**12米长、3米高木雕卧佛 = 世界最大**（印度尼西亚刺柏木，吉尼斯世界纪录）","**8米室外佛头雕塑**位于寺庙入口处 — 韩国最高","**3米玉佛** = 韩国最大","统一大钟 = 1988年汉城奥运会开幕时敲响的12吨青铜大钟，祈愿韩半岛统一","佛舍利由斯里兰卡、泰国、缅甸佛教团体赠予","**免费入场** + 提供寺院住宿（Templestay）体验项目","春季樱花 / 秋季红叶 — 拍摄最佳时节"],"timeUsed":["从水原星野购物中心乘坐大巴约30分钟可抵达龙仁卧牛精舍","在寺庙入口处进行简短的团体介绍（约5分钟）","自由参观路线：佛头 → 主殿 → 卧佛 → 铜钟 → 宝塔（约50–60分钟）","返回大巴集合（约10分钟）","可选体验：敲响统一大钟（1988年汉城奥运会开幕时敲响的12吨青铜大钟），许下统一心愿（欢迎捐款；约10分钟）"],"whyOnRoute":"第3条路线以山间寺院作结——宁静的精神体验，与华城的军事建筑及星野的商业现代感形成鲜明对比。**有别于一般韩国寺庙的独特定位**：卧牛精舍是一座建于1970年、融合泛亚佛教文化的折衷主义寺院（并非朝鲜王朝时期的传统寺庙）——这使其比深藏山中的传统寺庙更具视觉冲击力，也更适合游客参观。**免费入场**让整个行程更具性价比。龙仁莲花山的自然环境，加上从星野驱车约30分钟的路程，使其成为当日游程向西延伸的自然收尾，便于傍晚返程。以卧牛精舍作为一天的终点，将整体氛围从朝鲜世俗（华城）和21世纪商业（星野）转换为**20世纪佛教融合文化**——这座建于1970年、以祈愿统一为主旨的寺院，以其兼收并蓄的风格（印度檀香卧佛 + 斯里兰卡风格因陀罗瓦尔纳宝塔 + 缅甸进口黄铜佛像与白玉佛像 + 斯里兰卡/泰国/缅甸佛教团体赠予的佛舍利），与任何一座古老的韩国寺庙都截然不同，是返回首尔前黄昏时分理想的静思之所。**入场免费**（主殿欢迎捐款）。自驾：从水原星野经龙仁方向约50–60分钟。最佳摄影季节：**春季（4月–5月）樱花盛开**或**秋季（10月–11月）银杏与枫叶映衬寺院建筑**。","visitBasics":{"hours":"每日06:00–19:00（游客殿堂通常09:00–18:00开放）","closed":"全年开放","admission":"**免费**（欢迎捐款）；寺院住宿（Templestay）一晚约70,000–90,000韩元","walking":"难度适中——寺院建于山坡之上，各殿之间设有台阶；步行约500米，需爬升一定高度"},"convenience":{"restroom":"位于主殿及游客信息区附近","parking":"寺庙入口处设有免费停车场；可停放旅游大巴"},"smartNotes":{"photo":"入口处的**8米佛头像（佛头）**——卧牛精舍的标志性取景地，尤以秋叶为背景时更为壮观。主殿内的**3米木质卧佛**（世界最大木质卧佛）。斯里兰卡风格的**因陀罗瓦尔纳宝塔**。庭院中陈列着来自亚洲各地的佛像。**樱花（4月）或秋季红叶（10月–11月）**使寺院成为摄影爱好者的打卡胜地。","facilities":"游客信息中心、寺院住宿（Templestay）登记处、僧袍售卖区、念珠及佛教用品商店、素食斋堂（午餐约10,000韩元）。寺院后方设有莲花山登山步道（4公里环形路线，约需1.5小时）。","tip":"**免费入场**——与韩国其他主要寺庙相比，性价比极高。**有别于传统寺庙**——请向游客说明，这并非朝鲜王朝时期的寺庙，而是一座**建于1970年、融合泛亚文化的统一祈愿寺院**。**最佳摄影季节**：春季樱花（4月）或秋季红叶（10月下旬至11月上旬）。请着装端庄（遮住肩膀与膝盖）。入口处的8米佛头像是公认的最佳拍摄地点。**寺院住宿（Templestay）体验**是时间充裕的游客不可错过的独特项目——需提前通过templestay.com预约。"},"_poi_meta":{"poi_key":"waujeongsa_temple","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Visit Yongin","Templestay Korea","Korea Tourism Organization (english.visitkorea.or.kr — Waujeongsa Temple official listing)","Visit Yongin Tourism (yongin.go.kr/tour — Master Haedeung 1970 founding + reunification prayer temple)","Templestay Korea (templestay.com — Waujeongsa overnight program + 108-bow practice + sachal eumsik cuisine)","Wikipedia (Waujeongsa — pan-Asian Buddhist syncretism + Indravarna pagoda + Taepyeongjong 8-ton bell)","Korea Buddhism Yeonhwasan/Lotus-Mountain regional guide (Waujeongsa 와우 = ''reclining cow'' + sandalwood reclining Buddha origin)"]},"image":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","images":["/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp"],"imageCredits":[{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","location":"卧牛精舍","caption":"卧牛精舍 — photo 1","alt":"卧牛精舍 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","location":"卧牛精舍","caption":"卧牛精舍 — photo 2","alt":"卧牛精舍 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","location":"卧牛精舍","caption":"卧牛精舍 — photo 3","alt":"卧牛精舍 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","location":"卧牛精舍","caption":"卧牛精舍 — photo 4","alt":"卧牛精舍 — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","location":"卧牛精舍","caption":"卧牛精舍 — photo 5","alt":"卧牛精舍 — gallery image 5"}]}],"routeFlowStops":[{"name":"华城","type":"origin","theme":"联合国教科文组织历史遗迹"},{"name":"华城行宫","type":"primary","theme":"历史宫殿"},{"name":"星空图书馆","type":"primary","theme":"现代韩国"},{"name":"午餐","type":"meal","theme":"小憩"},{"name":"卧牛精舍","type":"return","theme":"心灵收尾"}],"routePhases":[{"phase":"联合国教科文组织世界遗产","duration":"第1站","description":"上午：联合国教科文组织遗产"},{"phase":"图书馆与午餐","duration":"第2–3站","description":"中午：图书馆与午餐"},{"phase":"山间寺庙收尾","duration":"第4站","description":"下午：山间寺庙收尾"}],"routeShapeIntro":{"title":"这一天的行程安排","subtitle":"约09:00在首尔两个集合点之一接客（通常为弘益大学站或明洞），上午参观联合国教科文组织遗产，中午游览现代图书馆并享用午餐，傍晚在龙仁以宁静的寺庙作为收尾。约18:00至19:00返回首尔。"},"whyTourWorks":{"bestFor":["希望在一天内同时体验历史遗产与现代风貌的韩国初访旅客","偏爱历史的旅行者及联合国教科文组织遗址打卡爱好者","摄影爱好者（华城城墙、星空广场中庭、佛像）","希望度过轻松平衡而非高强度活动日的情侣及成人家庭","希望参加含门票小团游的旅行者"],"routeLogicSections":[{"title":"为何选择这条水原—龙仁路线","icon":"landmark","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"一天跨越三个时代","detail":"朝鲜时代的联合国教科文组织建筑、当代韩国生活方式与山间佛教寺庙，一次涵盖韩国文化三个截然不同的面貌，无需走回头路。"},{"label":"紧凑的地理优势","detail":"华城、星空广场水原店与瓦宇精舍均位于首尔以南，彼此车程不超过30分钟，交通时间完全可控。"},{"label":"比单游华城更高的性价比","detail":"加入星空广场与寺庙，将单一景点之行升级为内容更丰富的全天游，而费用不会大幅增加。"}]},{"title":"实际步行强度体验","icon":"footprints","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"华城是最活跃的路段","detail":"城墙漫步是本线路体力消耗最大的环节，沿途有石阶和不平整地面。穿着合适的鞋子，大多数游客都能轻松应对。"},{"label":"Starfield 是休息时间","detail":"图书馆参观和午餐休息基本上是室内步行和休息时间，为全程提供了有益的午间恢复机会。"},{"label":"卧牛精舍属于中等强度","detail":"寺庙内有部分上坡路和台阶，但每段路程较短，主要佛像从入口处即可到达。"}]},{"title":"天气说明","icon":"cloud-rain","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"华城是对天气最敏感的景点","detail":"大雨或降雪会使城墙漫步体验变差；行宫室内宫殿是恶劣天气时的良好替代选择。"},{"label":"Starfield 是完全的天气缓冲站","detail":"图书馆和商场均为室内场所，因此这一站是雨天行程的理想避风港。"},{"label":"夏季湿度影响全天行程","detail":"城墙和寺庙区域均为露天场所；6月至8月期间请携带饮用水和防晒用品。"}]}],"lessIdealFor":["希望以逛商场购物为主的游客","不喜欢在石墙或寺庙小径上行走的游客","需要完全固定节奏且无需步行的游客","希望游览首尔中心宫殿的游客（本行程不进入首尔市区）"]},"practicalAccordionItems":[{"id":"pickup","title":"接送服务","preview":"首尔两处集合地点；约09:00出发","content":["通常在弘益大学站（4号出口）和明洞站接客","通常从第一集合地点于08:30至09:00出发","请在您所选集合地点提前至少10分钟到达","在首尔相同地点下车","预计于18:00至19:00之间返回，具体时间视交通状况及周日延误情况而定","本行程为固定路线团体形式，不含酒店接送；旅客须自行前往集合地点"]},{"id":"walking","title":"步行与地形","preview":"中等难度；华城城墙是主要体力消耗路段","content":["华城行宫：城墙步道及主要城门处设有石阶；历史地面凹凸不平","星空图书馆与购物中心：室内平坦地面，步行轻松","瓦宇亭寺：中等难度，部分路段需上坡及爬楼梯","建议穿着防滑舒适步行鞋","婴儿车仅可在星空购物中心使用；华城城墙及瓦宇亭寺不适合婴儿车通行"]},{"id":"weather","title":"天气政策","preview":"小雨可正常进行；大雨将影响城墙步道游览","content":["小雨：行程通常照常进行，视情况作常规调整","大雨或降雪：华城城墙步道可能缩短，改为游览华城行宫","星空购物中心为全室内景点，适合作为雨天备选站点","瓦宇亭寺部分区域为露天；小雨情况下寺庙照常开放"]},{"id":"wear","title":"穿着与携带物品","preview":"步行鞋、适合入寺的端庄服装、多层次穿搭","content":["防滑舒适步行鞋（游览华城及瓦宇亭寺必备）","参观寺庙须着端庄服装（建议遮盖肩部）","建议穿着多层次服装，以应对城墙露天区域与室内空间之间的温差变化","夏季请做好防晒并自备饮用水","建议携带相机或具备广角功能的手机，以拍摄星空图书馆特色美景"]},{"id":"included","title":"费用包含项目","preview":"含导游、交通及门票费用；午餐费用须现场自理","variant":"包含项目","content":["专业英语导游","首尔往返交通（小团包车）","所有门票费用（华城、华城行宫、星野广场免费、卧牛精舍）","午餐不含；请在星野广场餐厅自行付款","个人购物不含","自选咖啡馆消费不含","导游小费自愿"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"实时天气整合"},"tomorrow":{"temp":"—","label":"每日更新"}},"seasonalVariations":[{"season":"春季","title":"樱花季节","description":"四月初，樱花沿华城城墙盛开，是这条线路最佳拍摄季节之一。","icon":"flower"},{"season":"夏季","title":"郁郁葱葱，但潮湿炎热","description":"寺院绿意盎然，白昼时间较长，但湿热天气与城墙暴晒使上午行程更为辛苦。","icon":"sun"},{"season":"秋季","title":"最佳综合季节","description":"华城城墙与莲花山沿线能见度清晰，红叶缤纷，是这条线路综合体验最佳的季节之一。","icon":"leaf"},{"season":"冬季","title":"宁静而壮观","description":"寺院宁静，城墙壮观；天气寒冷但风景绝美。城墙段风吹当面，请注意保暖。","icon":"snowflake"}],"bookingTrustItems":[{"icon":"check-circle","title":"持牌本地运营商","description":"持有完整保险的韩国授权旅行社","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"路线专家","description":"精心定制的行程，而非千篇一律的环线游","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"精选团队规模","description":"根据路线合理控制人数","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"立即","title":"即时确认","detail":"预订确认及行程摘要"},{"timing":"出发前12小时","title":"12小时提醒","detail":"天气更新及路线调整通知"},{"timing":"出发前一晚","title":"最终接送信息","detail":"准确的接送时间及司机联系方式"},{"timing":"游览当天早晨","title":"当日路线说明","detail":"根据实时情况进行早间简报"},{"timing":"游览途中","title":"逐站游览贴士","detail":"每个景点的实时导览"},{"timing":"游览结束后","title":"游后支持","detail":"后续跟进与推荐"}],"staticQuestions":[{"id":"q1","question":"这与水原+民俗村或水原+光明洞窟游览有何不同？","answer":"三条路线均包含水原华城、华城行宫和星田图书馆。本路线新增龙仁卧牛精舍（佛教寺院，供奉3,000余尊佛像，拥有世界最大木雕卧佛）。民俗村路线新增韩国民俗村（270余座传统民居，韩剧拍摄地）。光明路线新增地下LED灯光洞窟公园。若您对佛教雕塑最感兴趣，推荐本路线；追求深度文化体验选民俗村路线；偏好多样性与室内活动选光明路线。"},{"id":"q2","question":"门票包含在内吗？","answer":"是的——三处收费景点门票均已包含：水原华城（成人1,000韩元）、华城行宫（成人1,500韩元）及卧牛精舍（免费入场）。星田图书馆对所有人免费开放。咖啡饮品、商场美食广场餐食及纪念品购买等费用需自理。"},{"id":"q3","question":"午餐包含在内吗？","answer":"不包含。午餐为星田水原商场美食广场的自由用餐时间——品类丰富，用餐轻松，人均消费约10,000至20,000韩元。图书馆及商场为第2站（约13:30抵达），时间安排自然衔接上午华城与下午卧牛精舍之间的休息节点。"},{"id":"q4","question":"卧牛精舍有何独特之处？","answer":"这是一座非传统寺院：由北韩难民僧侣金海根于1970年创立，围绕创始人收藏的3,000余尊亚洲各地佛像而建。镇寺之宝为\"佛头\"——高达8米的木雕佛首，已列入吉尼斯世界纪录，为全球最大；以及\"卧佛\"——以印度尼西亚桧木雕刻而成的3米×12米卧式佛像。重达12吨的统一大钟曾在1988年首尔奥运会开幕式上鸣响。免费入场，建议游览约75分钟。"},{"id":"q5","question":"参观寺庙需要注意着装吗？","answer":"建议在卧牛精舍着装时遮盖肩部——夏季穿无袖上衣时可携带一件薄外套。进入主殿通常需摘帽。室外寺庙区域无严格着装要求，但穿着得体是对寺庙的基本尊重。寺内台阶与坡道较多，建议穿着防滑舒适的步行鞋。"},{"id":"q6","question":"全天行程的步行量如何分配？","answer":"三段行程各有不同步行风格：华城城墙段难度最高（坡度较陡，城门处有台阶，步行约1公里）；星田图书馆全为室内，设有扶梯；卧牛精舍寺内有台阶与坡道（中等难度）。全天步行总量约3至4公里，城墙段与寺庙路段尤需穿着舒适步行鞋。"},{"id":"first-time","question":"初次游览水原和龙仁的游客适合选择此路线吗？","answer":"非常适合——对于希望在一天内游览一处UNESCO世界遗产、一处现代网红打卡空间及一座独具特色的佛教寺院的初次到访者而言，这是最受推荐的路线之一。行程节奏均衡，动静结合，各景点地理位置相近（水原-龙仁走廊，相距约30分钟车程）。提供弘大或明洞免费接送，出行简便轻松。"},{"id":"walking","question":"步行难度大吗？","answer":"中等活动强度。最难段为华城城墙：约1公里石砌城墙，坡度较陡，城门处有台阶，路面凹凸不平——务必穿着防滑舒适的步行鞋。星田图书馆步行轻松，全为室内平坦地面。卧牛精舍有部分上坡路段与台阶（中等难度）。全天步行总量约3至4公里。城墙段与寺庙不便使用婴儿车，星田内部可正常使用。"},{"id":"family","question":"此路线适合家庭出游吗？","answer":"适合——6岁及以上儿童的家庭均可舒适参与。华城城墙与卧牛精舍不便推行婴儿车，但星田全程设有扶梯和电梯，完全支持婴儿车通行。孩子们通常对卧牛精舍的巨型佛首及3,000余尊佛像印象深刻。在华城行宫租借韩服拍照是深受家庭喜爱的体验（并可免费入场参观城堡）。"},{"id":"seniors","question":"年长旅客参加方便吗？","answer":"对于能够应对台阶与不平整地面的活跃型老年人来说没有问题；行动不便者则有一定局限。华城城墙段难度最高（坡度陡、石台阶多）；老年人可选择平缓路段游览，跳过登上指挥台的攀爬部分。卧牛精舍有寺内台阶，但主要佛像展区位于无障碍楼层。星田全程设有扶梯和电梯，是全天行程中最轻松的休息站。"},{"id":"children","question":"建议的最低参与年龄是多少？","answer":"最适合6岁及以上儿童。城墙有台阶及不平整路面，卧牛精舍的寺庙坡道对幼龄儿童体力消耗较大。年龄稍大的孩子体验较好——巨型佛首与统一大钟极具视觉冲击力，星田图书馆也便于儿童游览。婴儿车在星田内使用方便，但不适用于城墙路段。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id 在运行时从 Supabase / 环境变量中解析；不属于静态 JSONB 的一部分。","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null}},"pickup_dropoff":{"departure":[{"order":1,"time":"08:30","name":"弘益大学站（4号出口）","type":"station","note":"首尔第一集合点；请提前10分钟到达。","lat":37.55753,"lng":126.92447},{"order":2,"time":"09:00","name":"明洞站","type":"station","note":"首尔第二集合点。","lat":37.56099,"lng":126.98619}],"return":[{"order":1,"name":"明洞站","type":"station","note":"首尔标准下车点。","lat":37.56099,"lng":126.98619},{"order":2,"name":"弘益大学站","type":"station","note":"首尔标准下车点。","lat":37.55753,"lng":126.92447}],"notes":["返回时间视交通状况而定，通常在18:00至19:00之间。为提高运营效率，下车顺序可能略有调整。请提前至少10分钟到达所选集合点。本行程采用固定集合点形式，不提供酒店接送。"]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-suwon-hwaseong-waujeongsa-starfield","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"gyeonggi_south","vehicle_type":"minicoach","duration_hours":9,"region_tags":["seoul_capital","gyeonggi_suwon","gyeonggi_yongin","gyeonggi_south","seoul_day_trip"],"theme_tags":["unesco","fortress","buddhist_temple","contemporary_architecture","k_drama_filming_location","first_time_friendly","iconic_landmarks","heritage_plus_modern"],"poi_tags":["hwaseong_fortress","hwaseong_haenggung","starfield_library_suwon","waujeongsa_temple","yeonhwasan"],"pace_level":0.6,"walking_level":0.6,"scenic_level":0.85,"photo_level":1,"culture_level":1,"relax_level":0.8,"first_time_fit":0.7,"family_fit":0.85,"senior_fit":0.75,"couple_fit":0.85,"solo_traveler_fit":0.95,"active_traveler_fit":0.5,"adult_family_fit":0.95,"family_with_teens_f