value":"良好","level":4},{"icon":"footprints","label":"步行","value":"適中","level":3},{"icon":"cloud-rain","label":"雨天安全","value":"良好","level":4},{"icon":"users","label":"適合家庭","value":"良好","level":4},{"icon":"gauge","label":"平衡","value":"均衡","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 1","caption":"水原華城 — 照片 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield 水原圖書館與購物中心","alt":"Starfield 水原圖書館與購物中心 — gallery image 1","caption":"Starfield 水原圖書館與購物中心 — photo 1"},{"id":3,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","location":"臥牛精舍","alt":"臥牛精舍 — gallery image 1","caption":"臥牛精舍 — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 2","caption":"水原華城 — 照片 2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 3","caption":"水原華城 — 照片 3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 4","caption":"水原華城 — 照片 4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","alt":"水原華城 — 圖庫圖片 5","caption":"水原華城 — 照片 5"},{"id":8,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield 水原圖書館與購物中心","alt":"Starfield 水原圖書館與購物中心 — gallery image 2","caption":"Starfield 水原圖書館與購物中心 — photo 2"},{"id":9,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield 水原圖書館與購物中心","alt":"Starfield 水原圖書館與購物中心 — gallery image 3","caption":"Starfield 水原圖書館與購物中心 — photo 3"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield 水原圖書館與購物中心","alt":"Starfield 水原圖書館與購物中心 — gallery image 4","caption":"Starfield 水原圖書館與購物中心 — photo 4"},{"id":11,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","location":"臥牛精舍","alt":"臥牛精舍 — gallery image 2","caption":"臥牛精舍 — photo 2"},{"id":12,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","location":"臥牛精舍","alt":"臥牛精舍 — gallery image 3","caption":"臥牛精舍 — photo 3"},{"id":13,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","location":"臥牛精舍","alt":"臥牛精舍 — gallery image 4","caption":"臥牛精舍 — photo 4"},{"id":14,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","location":"臥牛精舍","alt":"臥牛精舍 — gallery image 5","caption":"臥牛精舍 — photo 5"}],"itineraryStops":[{"number":1,"time":"≈ 10:00","duration":"75 分鐘","name":"水原華城","category":"聯合國教科文組織城塞","description":"**水原華城（수원화성）——自1997年起列入聯合國教科文組織世界遺產**——是韓國唯一一座保存有完整10冊施工記錄（《華城城役儀軌》，已於2007年另行列入聯合國教科文組織世界記憶名錄）的城牆城市。華城由正祖大王（정조，第22代朝鮮君王，在位\n\n1776-1800年）下令，**於1794至1796年僅歷時2年9個月**建造完成，是大王將朝鮮首都從漢陽（首爾）遷往水原的計畫——同時亦為紀念其父思悼世子，後者於1762年被其祖父英祖大王活封於米箱中。\n\n城塞由**丁若鏞（정약용，又號茶山）**設計——朝鮮實學（實用之學）學派的首席學者兼工程師——他將韓國傳統防禦建築、中國攻城防禦理論與新興的西方築城科學融為一體。\n\n丁若鏞發明了**舉重機（거중기）**——一種依據西方力學原理製成的滑輪起重機——用於施工期間搬運重石；這是韓國建築史上首次有文獻記載的西式現代工程技術應用。\n\n完整的城牆**周長5.74公里**，圍合130公頃，設有41座戰略設施：4座主城門（北門長安門——**韓國現存規模最大的王室城門**，大於首爾崇禮門；南門八達門；西門華西門；東門蒼龍門）、4座角樓、4座指揮所、5座哨台、5座砲台，以及射箭台、水門和烽火台。\n\n今日的導覽步行涵蓋**長安門（北主城門）至華西門（西城門，國寶第403號）之間最具攝影魅力的1.2公里路段**——軍事建築保存密度最高，步行約25至30分鐘。可登上八達山山頂的**西將台（西指揮所）**，俯瞰城塞最高景觀點，此亦為大王的戰略指揮位置。\n\n**華虹門（北水門）**以7座拱橋橫跨水原川，是城塞中拍攝最多的建築——尤其在春季（櫻花）和秋季（紅葉）時節。旅遊團徒步行走城牆；若行程允許，可選擇乘搭**華城御車**觀光小火車（成人4,000韓元，約30分鐘，練武台→八達門路線）。","highlights":["**自1997年起列入聯合國教科文組織世界遺產**——韓國唯一保存有原始施工記錄的城牆城市","由正祖大王（第22代朝鮮君王）於1794至1796年歷時2年9個月建造完成","由丁若鏞結合韓國、中國及西方築城科學設計而成","《華城城役儀軌》施工記錄——2007年列入聯合國教科文組織世界記憶名錄","周長5.74公里，設有41座戰略軍事設施","長安門北城門 — **韓國現存最大的王朝城門**","全長1.2公里導覽步行：長安門 → 華西門（拍照密度最高路段）","華虹門七拱水門 — 全區最多遊客拍照的標誌性建築","穿韓服者免費入場 + 每月最後一個週三免費 + 65歲以上長者免費"],"timeUsed":["遊覽車於長安門附近下客（約5分鐘）","於長安門進行簡短團體導覽說明（約5分鐘）","步行長安門 → 經華西將閣至華西門（約25-30分鐘）","自由拍照時間 + 於車輛處集合（約10分鐘）","可選搭華城列車觀光小火車：練武臺 ↔ 八達門（單程約30分鐘；₩4,000 成人）"],"whyOnRoute":"本路線的聯合國教科文組織世界遺產核心景點 — 韓國唯一保存完整的城郭都市，由正祖大王於1794至1796年間修建。長安門 → 華西門步行路段（約1.2公里）在75分鐘的停留時間內，集中呈現密度最高的保存完好軍事建築群，以及標誌性的華虹門七拱水門。之所以選擇此路段而非全程5.74公里環線，是因為此段涵蓋拍照價值最高、歷史意義最豐富的區域，同時為當天其餘三處文化遺址保留充裕時間。華城更是**任何水原一日遊的必訪核心**，因為城牆將行宮完整環繞其中，意即上午的水原行程便可獲得聯合國教科文組織世界遺產的歷史體驗與朝鮮王朝行宮的內部參觀，隨後行程繼續前往星野圖書館與臥牛精舍。長安門 → 經華西將閣至華西門的1.2公里城牆路段，是韓國保存最完整、軍事建築密度最高的步行路線（4座主城門 + 5座暗門 + 4處水門 + 舉重機建造的城牆，皆可在25至30分鐘步行時間內一覽無遺）。","visitBasics":{"hours":"城牆步道全天24小時開放（各城門除外）；建議遊覽時間：夏季09:00-18:00 / 冬季09:00-17:00；夜間開放時間：5月至10月週三至週日 18:00-21:30","closed":"全年開放（華城列車週一休息）","admission":"成人 1,000 / 青少年 700 / 兒童 500 韓圜（免費：6歲以下兒童、65歲以上長者、穿韓服者、每月最後一個週三）。華城列車另收 4,000 韓圜","walking":"中等難度 — 西將臺附近城牆坡度較陡；各城門設有階梯；部分路段輪椅通行困難"},"convenience":{"restroom":"設於長安門、華西門、八達門及練武臺","parking":"遊覽車於長安門停車場下客；練武臺設有指定遊覽車停車區"},"smartNotes":{"photo":"**華虹門（北側水門）**橫跨水原川的七道拱橋 — 尤以春季（櫻花盛開）及秋季（楓葉）時最為迷人，為全區最經典的拍照地點。**長安門（韓國現存最大的王朝城門）**於黃金時段（日落前後）最為壯觀。**西將臺（西側指揮所）**可欣賞八達山夕陽美景。","facilities":"遊客服務中心位於長安門、八達門及華城行宮廣場。全區設有英韓雙語指示牌。長安門備有華城語音導覽租借服務。","tip":"請穿著舒適的鞋子 — 城牆石面凹凸不平。於行宮廣場租借韓服可免費進入城堡及宮殿。**除非安排2.5小時以上，否則建議避免走完全程5.74公里環線** — 長安門 → 華西門路段每公尺的文化遺產密度最高。"},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","KoreaToDo","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","caption":"水原華城 — 照片 1","alt":"水原華城 — 相冊圖片 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","caption":"水原華城 — 照片 2","alt":"水原華城 — 相冊圖片 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","caption":"水原華城 — 照片 3","alt":"水原華城 — 相冊圖片 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","caption":"水原華城 — 照片 4","alt":"水原華城 — 相冊圖片 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","caption":"水原華城 — 照片 5","alt":"水原華城 — 相冊圖片 5"}]},{"number":2,"time":"≈ 11:30","duration":"75 分鐘","name":"華城行宮","category":"朝鮮王朝離宮","description":"**華城行宮（화성행궁）——韓國現存規模最大的行宮（離宮）** — 於1789年至1796年間，在正祖大王的主導下，作為華城統一防禦城市計畫的一部分而建成。\n\n**行宮**是朝鮮國王出巡、避難或舉行特別儀式時所使用的臨時離宮；華城行宮的規模超越溫陽、北漢山及南漢山行宮。正祖大王建造此行宮，主要是為了前往祭拜其遭賜死的父親思悼世子的陵墓（顯隆園，現稱融陵，位於南方4公里處）時能夠留宿，他在位期間共進行了**13次謁陵之行**。\n\n其中最為著名的是**1795年的王室出巡**，隨行人員達6,000名、馬匹1,400匹，為惠慶宮洪氏（國王之母，亦是思悼世子之遺孀）慶祝六十大壽。\n\n1795年的出巡詳細記錄於**《園幸乙卯整理儀軌》——自2007年起列入聯合國教科文組織世界記憶名錄**。行宮原有**576間（房間／結構間）**，功能齊全，如同一座完整的縮小版王室居所，設有正殿（奉壽堂）、副殿（洛南軒）、寢殿（長安軒）、御廚、軍事辦公室及衛兵房。\n\n**日本殖民時期（1910-1945年）行宮大規模遭到破壞**，日本人將行宮用地改建為水原道立醫院及警察署。\n\n**修復工程於1996年啟動**，依據原始的《華城城役儀軌》施工記錄進行；第一期工程於2003年完工（奉壽堂、洛南軒、長安軒、維旅宅），第二期工程於2009年完工（羽華館御廚、新豐樓入口城門）。修復工程至今仍持續進行中。\n\n**重要歷史說明：洛南軒（낙남헌）是唯一保存自1796年原始建築的建物** — 日本人雖將其改作警察署辦公室，但並未拆除。因此，它是園區內唯一**真正的原始木造瓦頂建築**，其餘建物均為後世重建。\n\n**每日王室衛兵交接典禮**於新豐樓城門舉行 — **週二至週日上午11:00**（視天氣而定），約15分鐘，**免費**。重現朝鮮時代的宮門交接儀式，衛兵身穿紅、藍、黃色服裝，並伴有傳統鼓樂與號角。\n\n行程安排將視當日星期配合11:00典禮的時間抵達。此地曾作為韓劇**《大長今》（2003年）**的拍攝地點——這部朝鮮時代的經典巨作在 MBC 創下約 57% 的最高收視率——使其成為韓國最具代表性的宮廷劇取景地之一。","highlights":["**韓國現存規模最大的行宮（離宮）** — 原有576間房","於正祖大王在位期間，1789年至1796年間與華城同步建造","正祖大王為祭拜其遭賜死的父親思悼世子，曾13次親臨此地謁陵","**洛南軒 = 唯一保存至今的1796年原始建築**（其餘均為後世重建）","**王室衛兵交接典禮 週二至週日上午11:00 新豐樓城門（免費，約15分鐘）**","1795年王室出巡記錄已列入聯合國教科文組織世界記憶名錄","韓劇《大長今》（2003年 MBC，最高收視率約57%）拍攝地","身著韓服者、65歲以上長者及6歲以下兒童**免費**入場","**洛南軒（낙남헌）是1796年原始建築中唯一倖存至今的建築** ——日本殖民時期當局將其改作警察署辦公室，但並未將其拆除；今日所見行宮內其他所有建築，均為1996年後依據《華城城役儀軌》（2007年列入聯合國教科文組織《世界記憶名錄》）重建而成"],"timeUsed":["距華城城牆（華西門一帶）步行約5分鐘","請提前安排好時間，趕上新豐樓 **上午11:00王室衛兵換崗儀式**（約15分鐘）","奉壽堂正殿＋洛南軒＋長安軒步行參觀（約30分鐘）","拍照留念＋返回車輛集合（約15分鐘）","可選行程：新豐樓城門王室衛兵換崗儀式（週二至週日上午11:00，約15分鐘，免費——視天氣狀況而定）"],"whyOnRoute":"與城牆遊覽形成天然搭配——這座臨時王室行宮位於同一聯合國教科文組織遺址範圍內，兩處相距僅5分鐘。這裡是韓國最大的行宮（原有576間房），其中**洛南軒是唯一保存原貌的真實建築**（其餘均為1996年後依照《華城儀軌》重建）。請安排好抵達時間，以趕上王室衛兵換崗儀式（週二至週日上午11:00），儀式全程免費、約15分鐘，是本行程目錄中最具吸引力的免費文化體驗之一。在參觀城牆後立即前往行宮，可將抽象的軍事建築知識轉化為親身感受的朝鮮王朝皇室空間體驗——奉壽堂正殿於1795年曾是正祖大王接見官員之處，同時也是他為母親惠慶宮洪氏舉辦盛大六十大壽宴席的場所（此景記載於《儀軌》所收錄的《班次圖》宮廷畫卷之中）。**城牆＋行宮聯票**售價3,500韓元（分開購票合計2,500韓元）——是水原站點一個具體可感的超值亮點。新豐樓城門王室衛兵換崗儀式（週二至週日上午11:00，約15分鐘，免費）的時間安排，與大多數從首爾出發一日遊抵達水原的行程時刻表高度吻合。","visitBasics":{"hours":"09:00–18:00（最後入場17:30）；夏季5月至10月夜間延長開放18:00–21:00","closed":"全年開放","admission":"成人1,500韓元／青少年1,000韓元／兒童700韓元。城牆＋行宮聯票3,500韓元。身著韓服者、65歲以上長者及6歲以下兒童免費","walking":"輕鬆——宮殿園區地勢大多平坦，各庭院之間設有少許台階"},"convenience":{"restroom":"設於正門入口、奉壽堂附近及行宮廣場","parking":"華城行宮公共停車場；行宮廣場收費停車場"},"smartNotes":{"photo":"**奉壽堂正殿** ——標誌性正殿拍攝地。**洛南軒** ——唯一的1796年原始建築（最具歷史真實感的拍照地點）。**新豐樓城門王室衛兵換崗儀式**（週二至週日上午11:00）。身著韓服者於新豐樓前留影——水原最受歡迎的韓服拍照勝地。","facilities":"遊客服務中心、洗手間、禮品店。行宮廣場咖啡廳及韓服租借（4小時15,000至20,000韓元）。水原烤全雞（통닭）餐廳步行5分鐘可達。","tip":"**請安排好時間，趕上週二至週日上午11:00王室衛兵換崗儀式（免費）**。租借韓服可同時享有城牆與行宮兩處免費入場資格。**洛南軒是歷史上最重要的單一景點** ——唯一未經重建、歷經日本殖民統治拆除威脅而倖存下來的建築。請避開週一前往——王室衛兵換崗儀式僅於週二至週日舉行。"},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"水原華城","caption":"水原華城 — 照片 1","alt":"水原華城 — 圖庫圖片"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"水原華城","caption":"水原華城 — 照片 2","alt":"水原華城 — 圖庫圖片"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"水原華城","caption":"水原華城 — 照片 3","alt":"水原華城 — 圖庫圖片"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"水原華城","caption":"水原華城 — 照片 4","alt":"水原華城 — 圖庫圖片"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"水原華城","caption":"水原華城 — 照片 5","alt":"水原華城 — 圖庫圖片"}]},{"number":3,"time":"≈ 13:30","duration":"90 分鐘","name":"Starfield 水原圖書館與購物中心","category":"現代文化地標 + 午餐","description":"**Starfield 水原圖書館（별마당 도서관 수원）** — 位於 **Starfield 水原**，這是新世界地產旗下**「第二代」Starfield 旗艦購物中心，於2024年1月26日正式開業**，為新世界地產旗下第五座 Starfield 購物中心；總投資額超過1兆韓元（約7.5億美元）；總建築面積約334,000平方公尺，為韓國第二大室內購物中心，僅次於 Starfield 河南。\n\n由 **BCHO Partners（趙秉洙）** 合作設計——這家韓國建築事務所曾打造原版 COEX Starfield 圖書館（2017年）——水原圖書館是第二代升級版本，擁有**高達22公尺的書架**，是韓國任何公共空間中最高的圓柱形書架結構之一。\n\n圖書館橫跨**4個樓層（1F至4F中庭挑空）**，收藏約**70,000冊書籍與雜誌**，涵蓋韓國及國際出版品、期刊、藝術書籍，4F並設有專屬兒童文學區。\n\n**免費對外開放** — 無需借書證，免費入場，隨購物中心營業時間開放參觀。特色亮點：**黑膠唱片試聽休息區**，精選韓國獨立音樂及爵士樂／經典搖滾黑膠唱片；**每月輪換藝術展覽**陳列於中庭空間；以及**中庭季節性櫻花裝置藝術（3月至4月）**，數千片粉色LED花瓣構成夢幻景致——是水原最受歡迎的春季打卡景點之一。\n\n**本90分鐘行程包含午餐**，於 **Eatopia 美食廣場（B1F）**享用，設有30多家餐廳，涵蓋快餐韓食（5,000–10,000韓元）至中價位韓式及國際料理（15,000–25,000韓元）。韓式烤肉、拌飯、刀削麵、餃子、日式炸豬排、韓墨融合料理（Ko-Mex）、Mountain Bus 澳洲漢堡、越南河粉、水餃——料理種類應有盡有。\n\n周邊購物中心設施：**Aquafield 水原水上樂園 + 韓式溫泉（B1–2F）**，需另行購票，約25,000–35,000韓元；**玩具王國（4F，韓國最大玩具店）**；**CGV／MEGABOX 雙影院配置**。\n\n**Starfield 免費接駁巴士**從水原站4號出口每10至15分鐘發車（車程約10分鐘）——是大眾運輸前往最便捷的方式。年訪客量：**首年（2024年）約2,800萬人次** — 位居韓國三大最受歡迎購物目的地之列。","highlights":["**新世界旗艦第二代 Starfield 購物中心 — 2024年1月26日開業**","由BCHO Partners設計（同為2017年原版COEX星空圖書館的設計單位）","**四層圖書館，設有22公尺高書架** — 為韓國最高圓柱形書架之一","約70,000冊書籍及雜誌，免費開放閱覽","黑膠唱片聆聽休息室","櫻花LED花瓣裝置藝術（三月至四月）","**行程包含午餐** — B1F Eatopia美食廣場設有30間以上餐廳","Aquafield水上樂園＋韓式汗蒸幕、Toy Kingdom玩具王國（韓國最大）、CGV＋MEGABOX電影院","從水原站4號出口搭乘Starfield免費接駁車（約10分鐘）","開幕首年（2024年）訪客人數約達2,800萬人次"],"timeUsed":["從水原華城乘遊覽車前往Starfield水原，車程約30分鐘","於Eatopia美食廣場用午餐（約30至45分鐘）","圖書館＋中庭漫步＋拍照時間（約30至40分鐘）","短暫逛街購物＋返回遊覽車集合（約10至15分鐘）","可選擇於Eatopia美食廣場用午餐（B1F，30間以上韓式及國際餐廳；每人約₩10,000-25,000；45至60分鐘）"],"whyOnRoute":"作為上午UNESCO世界遺產行程後的「現代韓國」對應點。**圖書館＋午餐合併站**是第3號行程的設計核心——善用Eatopia美食廣場解決午餐（省去獨立餐廳停靠）。圖書館及22公尺高書架為建築展示亮點，全室內環境亦可應對正午天氣風險。**午餐就在Starfield的Eatopia美食廣場享用** — 90分鐘合併站自然融入緊湊的四站式行程。作為行程中段的轉換站，Starfield圖書館在華城（深厚的歷史建築內容）與臥牛精舍（精緻的宗教融合內容）之間，充當**建築與休閒的喘息空間** — 22公尺中庭書架以**免費入場**提供令人滿足的打卡體驗，周邊商場（600間以上品牌、Eatopia美食廣場、Aquafield水上樂園）更提供彈性的午餐＋洗手間＋咖啡廳＋購物休息安排，此為華城及臥牛精舍均無法直接提供的便利條件。","visitBasics":{"hours":"商場營業時間10:00-22:00；圖書館於商場開放期間全程可進入","closed":"每月休館1至2天（通常為週一 — 請上網確認）","admission":"圖書館免費入場；Eatopia美食廣場按消費付費（午餐每人約5,000-25,000韓元）","walking":"無障礙設計 — 各樓層均設有電扶梯及電梯；輪椅及嬰兒車全館通行無阻"},"convenience":{"restroom":"每層樓均設有多處洗手間；備有家庭友善設施","parking":"地下停車場約5,000個車位；購物滿30,000韓元以上可享前3小時免費停車；設有團體遊覽車專用停車區"},"smartNotes":{"photo":"**圖書館中央中庭22公尺高書架** — 從4樓藝廊俯瞰最佳角度。**黑膠唱片休息室**呈現復古美學。**中庭櫻花裝置（三月至四月）** — 熱門季節打卡照。聖誕樹（十二月）。4樓兒童專區適合家庭拍照留念。","facilities":"Eatopia美食廣場B1F（30間以上餐廳，5,000-40,000韓元）、4F Toy Kingdom玩具王國、B1-2F Aquafield水上樂園、CGV＋MEGABOX電影院、免費WiFi、多語種客戶服務、主要門店設有退稅服務台。","tip":"**圖書館全程免費**（商場開放期間）。**22公尺高書架 = 韓國最高圖書館書架**（向旅客提及以加深印象）。**三月至四月櫻花裝置**為當季必訪亮點。**Eatopia美食廣場午餐** — 無需預訂；建議13:00-13:30前往以避開韓國午餐高峰期。避開週六下午（人潮最密集時段）。出發前請上網確認Starfield當月休館日期。"},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["Starfield official","VisitKorea","Shinsegae press","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Starfield 水原圖書館與購物中心","caption":"Starfield 水原圖書館與購物中心 — photo 1","alt":"Starfield 水原圖書館與購物中心 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Starfield 水原圖書館與購物中心","caption":"Starfield 水原圖書館與購物中心 — photo 2","alt":"Starfield 水原圖書館與購物中心 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Starfield 水原圖書館與購物中心","caption":"Starfield 水原圖書館與購物中心 — photo 3","alt":"Starfield 水原圖書館與購物中心 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Starfield 水原圖書館與購物中心","caption":"Starfield 水原圖書館與購物中心 — photo 4","alt":"Starfield 水原圖書館與購物中心 — gallery image 4"}]},{"number":4,"time":"≈ 15:30","duration":"75 分鐘","name":"臥牛精舍","category":"佛教寺院（現代折衷主義風格）","description":"**臥牛精舍（와우정사）** — **由金海根（김해근）僧人於1970年創建**，作為韓戰（1950-1953）導致朝鮮半島分裂後，與本山寺院天各一方的北韓佛教僧侶之避難所。\n\n該寺廟最初以「千寺佛」（字面意思為「千零一尊佛的寺廟」）之名創立，以佛教三十三護法神為基礎，乘以韓國統一祈願之倍數，作為對佛教神明的致敬。\n\n**臥牛（와우，臥牛）** = 「臥伏的牛」——源自附近蓮花山（연화산）的地形，從遠處望去形似一頭臥伏的牛。\n\n**精舍（정사，精舍）** = 「寺廟」（佛教精舍）。因此完整名稱譯為「臥牛精舍」。**韓國建築風格最具特色的佛教寺廟之一** — 折衷融合式設計，融入印度、斯里蘭卡、泰國、緬甸（Burma）、西藏、中國及韓國等各地佛教傳統的建築元素。\n\n寺內陳列約3,000尊來自亞洲各佛教國家的佛像，遍布整個園區。**這並非典型的韓國朝鮮時代寺廟**，而是建於1970年的統一祈願寺廟——請向賓客說明此一區別。標誌性特色：**12公尺長、3公尺高木製臥佛（臥佛／와불）**，由單棵印尼刺柏木雕刻而成——**世界最大木製臥佛**（金氏世界紀錄）；**8公尺高戶外佛頭雕像（佛頭，불두）**，位於寺廟入口，以青銅製成並覆以金箔，為韓國最高的佛頭雕像之一；**3公尺高坐姿玉佛**，由從緬甸進口的白玉雕刻而成——韓國最大玉佛；以及**梵帝殿正殿**，供奉一尊從緬甸進口的8公尺高銅佛。\n\n**統一大鐘（통일대종）** — 1988年漢城奧運開幕時敲響的12噸青銅大鐘，為韓國統一祈願而鑄；遊客可親自敲響此鐘（歡迎隨喜捐獻）。\n\n**因陀羅婆那塔（인드라바르나탑）**，採斯里蘭卡式設計，外覆白色灰泥。**塔內供奉由斯里蘭卡、泰國及緬甸佛教教團贈予的佛陀舍利** — 是一份獨特的佛教國際外交禮物。\n\n**免費入場**。設有**寺院住宿體驗（Templestay）**（含一夜住宿、僧侶帶領修行、傳統108拜、禪修、佛教齋食、傳統茶道——可透過templestay.com預訂，每晚約70,000至90,000韓元）。\n\n**最佳攝影季節：春季櫻花（四月）及秋季楓葉（十月至十一月）** — 金黃銀杏與火紅楓葉相互映襯，為寺廟建築增添絕美景致。\n\n寺廟園區依山坡而建，各殿堂之間設有石階；步行距離約500公尺，途中需爬升一定高度。","highlights":["**由金海根（김해근）僧人於1970年創建，作為韓國統一祈願寺廟**","折衷融合式設計——泛亞洲佛教風格（印度、斯里蘭卡、泰國、緬甸、西藏、中國、韓國）","約3,000尊來自亞洲各佛教國家的佛像","**12公尺長、3公尺高木製臥佛 = 世界最大**（印尼刺柏木，金氏世界紀錄）","**8公尺高戶外佛頭雕像**，位於寺廟入口——韓國最高","**3公尺玉佛** = 韓國最大","統一大鐘 = 1988年漢城奧運開幕時敲響的12噸青銅大鐘，為韓半島統一祈願而鑄","佛舍利（舍利子）由斯里蘭卡、泰國、緬甸佛教僧團敬贈","**免費入場** + 提供寺院住宿（Templestay）體驗","春季櫻花 / 秋季紅葉 — 攝影絕佳時節"],"timeUsed":["從水原Starfield搭乘遊覽車，約30分鐘可抵達龍仁臥牛精舍","於寺廟入口進行簡短集體說明（約5分鐘）","自由參觀：佛頭 → 主殿 → 臥佛 → 銅鐘 → 佛塔（約50–60分鐘）","返回遊覽車集合（約10分鐘）","可選體驗：敲響統一大鐘（1988年漢城奧運開幕時敲響的12噸青銅大鐘），祈願統一（歡迎捐獻；約10分鐘）"],"whyOnRoute":"第3行程以山間寺廟作結——與華城的軍事建築及Starfield的商業現代感形成寧靜的精神對比。**與一般韓國寺廟的顯著差異**：臥牛精舍是1970年建成的綜合泛亞佛教融合寺廟（並非朝鮮時代的傳統寺廟），因此比深山中的傳統寺廟更具視覺衝擊力，也更便於遊客參觀。**免費入場**讓行程更加省錢實惠。龍仁蓮花山的自然環境，加上距Starfield約30分鐘車程，使其成為當天環形路線向西自然延伸的合理選擇，便於傍晚返程。在臥牛精舍結束一天的行程，使整體氛圍從朝鮮世俗（華城）和21世紀商業（Starfield）轉換至**20世紀佛教融合風格**——這座1970年創建、以祈願統一為宗旨的寺廟，其折衷融合的風格（印度白檀臥佛＋斯里蘭卡式因陀羅槃那塔＋緬甸進口黃銅與白玉佛像＋斯里蘭卡／泰國／緬甸佛教舍利敬贈），與任何古老的韓國寺廟截然不同，是返回首爾前傍晚時分靜思冥想的理想場所。**入場免費**（主殿歡迎捐獻）。自駕：從水原Starfield經龍仁方向約50–60分鐘。最佳攝影季節：**春季（4–5月）櫻花**或**秋季（10–11月）銀杏＋楓葉映襯寺廟建築**。","visitBasics":{"hours":"每日 06:00–19:00（開放參觀的殿堂通常為 09:00–18:00）","closed":"全年開放","admission":"**免費**（歡迎捐獻）；寺院住宿（Templestay）一晚約 70,000–90,000 韓元","walking":"中等難度——寺廟位於山坡上，各殿堂之間設有台階；步行約500公尺，具一定爬升高度"},"convenience":{"restroom":"位於主殿及遊客服務中心附近","parking":"寺廟入口處設有免費停車場；可容納旅遊大型巴士"},"smartNotes":{"photo":"入口處的**8公尺佛頭（佛頭像）**——臥牛精舍最具代表性的拍攝景點，尤以秋季紅葉為背景時最為壯觀。主殿內的**3公尺木製臥佛**（世界最大的木製臥佛）。斯里蘭卡風格的**因陀羅槃那塔**。庭院中陳列來自亞洲各地的佛像。**櫻花（4月）或秋季紅葉（10–11月）**使寺廟成為攝影愛好者的熱門目的地。","facilities":"遊客服務中心、寺院住宿報名處、袈裟僧袍販售區、念珠及佛教用品商店、素食寺廟料理餐廳（午餐約10,000韓元）。寺廟後方設有蓮花山登山步道（4公里環形路線，約1.5小時）。","tip":"**免費入場**——相較於其他主要韓國寺廟，性價比極高。**有別於傳統寺廟**——請向賓客說明，此處並非朝鮮時代的傳統寺廟，而是**1970年建成的折衷泛亞統一祈願寺廟**。**最佳攝影季節**：春季櫻花（4月）或秋季紅葉（10月下旬至11月上旬）。請穿著端莊服裝（遮蓋肩膀及膝蓋）。入口處的8公尺佛頭是公認最具代表性的拍照地點。**寺院住宿體驗（Templestay）**對有充裕時間的賓客而言是難得的體驗——需事先於 templestay.com 完成預訂。"},"_poi_meta":{"poi_key":"waujeongsa_temple","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Visit Yongin","Templestay Korea","Korea Tourism Organization (english.visitkorea.or.kr — Waujeongsa Temple official listing)","Visit Yongin Tourism (yongin.go.kr/tour — Master Haedeung 1970 founding + reunification prayer temple)","Templestay Korea (templestay.com — Waujeongsa overnight program + 108-bow practice + sachal eumsik cuisine)","Wikipedia (Waujeongsa — pan-Asian Buddhist syncretism + Indravarna pagoda + Taepyeongjong 8-ton bell)","Korea Buddhism Yeonhwasan/Lotus-Mountain regional guide (Waujeongsa 와우 = ''reclining cow'' + sandalwood reclining Buddha origin)"]},"image":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","images":["/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp"],"imageCredits":[{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","location":"臥牛精舍","caption":"臥牛精舍 — photo 1","alt":"臥牛精舍 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","location":"臥牛精舍","caption":"臥牛精舍 — photo 2","alt":"臥牛精舍 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","location":"臥牛精舍","caption":"臥牛精舍 — photo 3","alt":"臥牛精舍 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","location":"臥牛精舍","caption":"臥牛精舍 — photo 4","alt":"臥牛精舍 — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","location":"臥牛精舍","caption":"臥牛精舍 — photo 5","alt":"臥牛精舍 — gallery image 5"}]}],"routeFlowStops":[{"name":"華城","type":"origin","theme":"世界遺產的過往"},{"name":"華城行宮","type":"primary","theme":"歷史宮殿"},{"name":"星空圖書館","type":"primary","theme":"現代韓國"},{"name":"午餐","type":"meal","theme":"重置"},{"name":"臥牛精舍","type":"return","theme":"靈性收尾"}],"routePhases":[{"phase":"世界文化遺產","duration":"第 1 站","description":"上午：UNESCO 世界遺產"},{"phase":"圖書館與午餐","duration":"第 2–3 站","description":"午間：圖書館與午餐"},{"phase":"山間寺廟作結","duration":"第 4 站","description":"下午：山間寺廟作結"}],"routeShapeIntro":{"title":"這一天的行程節奏","subtitle":"約 09:00 於首爾兩個集合地點之一出發接送（通常為弘益大學站或明洞），上午參觀 UNESCO 世界遺產，午間前往現代圖書館享用午餐，最後於龍仁以寧靜寺廟作結。約 18:00 至 19:00 返回首爾。"},"whyTourWorks":{"bestFor":["希望一天內同時體驗歷史遺產與現代風貌的首次訪韓旅客","偏好歷史文化的旅客及 UNESCO 景點蒐集愛好者","攝影愛好者（華城城牆、Starfield 中庭、佛像）","希望享受輕鬆均衡而非體力消耗型行程的情侶與成人家庭","希望以小團體形式出遊且含門票費用的旅客"],"routeLogicSections":[{"title":"為何水原—龍仁路線如此出色","icon":"landmark","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"一日走過三個時代","detail":"朝鮮時代的 UNESCO 建築、當代韓國生活風貌，以及山中佛教寺廟，在行程不重複折返的情況下，帶您領略韓國文化截然不同的三個面向。"},{"label":"地理位置高度集中","detail":"華城、Starfield 水原與臥牛精舍均位於首爾以南，三地之間車程在 30 分鐘以內，交通時間十分從容。"},{"label":"比單獨遊覽華城更具價值","detail":"加入 Starfield 與寺廟，讓原本的單一景點之旅升級為更豐富的全日行程，費用卻不會大幅提升。"}]},{"title":"實際步行量的體感","icon":"footprints","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"華城是活動量最多的路段","detail":"城牆步道是本路線主要的體力挑戰，途中有石階與不平整路面。穿著合適的鞋子，大多數旅客均能順利完成。"},{"label":"Starfield 是休息時間","detail":"圖書館與午餐休息實質上以室內步行及靜坐為主，為行程帶來實用的午間恢復時段。"},{"label":"臥牛精舍屬於中等強度","detail":"寺廟園區有部分上坡路段與階梯，但各段路程均不長，從入口即可抵達主佛像。"}]},{"title":"天氣注意事項","icon":"cloud-rain","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"華城是天氣影響最大的景點","detail":"大雨或降雪會使城牆步行較不舒適；天氣不佳時，行宮（Haenggung）室內宮殿是很好的替代選擇。"},{"label":"Starfield 完全不受天氣影響","detail":"圖書館與購物中心均為室內環境，此站是雨天行程的理想據點。"},{"label":"夏季高濕度會影響當天行程","detail":"城牆與寺廟園區皆為露天環境；6月至8月間請自備飲水與防曬用品。"}]}],"lessIdealFor":["偏好以逛街購物為主的旅客","不喜歡行走石牆或寺廟小徑的遊客","需要全程固定步調且無需步行的旅客","希望參觀首爾市中心宮殿的旅客（本行程主要在首爾市外）"]},"practicalAccordionItems":[{"id":"pickup","title":"上車與下車","preview":"兩個首爾集合地點；約09:00出發","content":["上車地點通常為弘益大學站（4號出口）及明洞站","出發時間通常為第一集合地點的08:30至09:00","請至少提前10分鐘抵達您所選的集合地點","下車地點與上車的首爾集合地點相同","預計於18:00至19:00之間返回，實際時間視交通狀況及週日延誤而定","本行程為固定路線團體形式，不提供飯店接送；旅客須自行前往集合地點"]},{"id":"walking","title":"步行與地形","preview":"中等強度；華城城牆為主要體力消耗路段","content":["華城（水原華城）：城牆步道及主要城門設有石階；歷史地面高低不平","星際廣場圖書館與購物中心：室內平坦地面，步行輕鬆","臥牛精舍：中等強度，部分路段有上坡及階梯","建議穿著防滑舒適的步行鞋","嬰兒車僅可於星際廣場使用；華城城牆及臥牛精舍不適合推嬰兒車進入"]},{"id":"weather","title":"天氣政策","preview":"小雨可正常進行；大雨將縮短城牆步行行程","content":["小雨：行程通常照常進行，視情況作一般調整","大雨或降雪：華城城牆步行路段可能縮短，改以行宮（華城行宮）為主要景點","星際廣場為全室內景點，可作為雨天備用據點","臥牛精舍部分為露天區域；小雨時寺院活動仍照常進行"]},{"id":"wear","title":"穿著與攜帶物品建議","preview":"步行鞋、合宜的寺院服裝、保暖分層衣物","content":["防滑舒適的步行鞋（參觀華城及臥牛精舍時為必備）","參觀寺院請穿著端莊服裝（建議遮蓋肩膀）","可分層穿搭的輕薄衣物，以應對城牆露天區域與室內空間的溫差變化","夏季請備妥防曬用品及飲用水","相機或具備廣角功能的手機，以拍攝星際廣場圖書館的壯觀景緻"]},{"id":"included","title":"費用包含項目","preview":"包含導覽、交通及門票；午餐費用需現場自付","variant":"包含項目","content":["專業英語導覽員","首爾來回交通（小團體車輛）","所有門票費用（華城、華城行宮、Starfield 免費、臥牛精舍）","午餐不含；請直接於 Starfield 購物中心餐廳自行付款","個人購物不含","自選咖啡廳消費不含","導遊小費自由給付"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"即時天氣整合"},"tomorrow":{"temp":"—","label":"每日更新"}},"seasonalVariations":[{"season":"春季","title":"賞櫻季節","description":"四月初，櫻花盛開於華城城牆兩側，是此路線攝影的最佳季節之一。","icon":"flower"},{"season":"夏季","title":"繁茂但潮濕","description":"寺院綠意盎然、日照時間較長，但高濕度與城牆日曬使上午路段更為費力。","icon":"sun"},{"season":"秋季","title":"最佳全方位季節","description":"華城城牆與蓮花山沿途視野清晰、楓紅繽紛，是此路線最出色的全方位季節之一。","icon":"leaf"},{"season":"冬季","title":"寧靜而壯麗","description":"寺院靜謐、城牆壯觀，天氣寒冷但視覺享受十足。城牆步道無遮蔽，請務必做好保暖。","icon":"snowflake"}],"bookingTrustItems":[{"icon":"check-circle","title":"持照在地旅遊業者","description":"具備完整保險之韓國合法旅遊業者","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"路線專家","description":"精心調製的行程，非千篇一律的套裝路線","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"精選團體人數","description":"依路線配置最適人數","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"立即","title":"即時確認","detail":"附行程摘要的預訂確認通知"},{"timing":"出發前12小時","title":"12小時前提醒","detail":"天氣更新及路線調整通知"},{"timing":"前一天傍晚","title":"最終接送資訊","detail":"確切接送時間與司機聯絡方式"},{"timing":"行程當天早上","title":"當日路線說明","detail":"依即時狀況提供的行前早晨簡報"},{"timing":"行程進行中","title":"逐站小提示","detail":"各景點即時導覽引導"},{"timing":"行程結束後","title":"行程後支援服務","detail":"後續跟進與推薦建議"}],"staticQuestions":[{"id":"q1","question":"這與水原＋民俗村或水原＋光明洞窟行程有何不同？","answer":"三條路線均包含水原華城城廓＋華城行宮＋星空圖書館。本路線另加龍仁臥牛精舍（佛教寺院，3,000餘尊佛像，世界最大木雕臥佛）。民俗村路線另加韓國民俗村（270餘棟傳統建築，韓劇拍攝地）。光明路線另加地下LED洞窟公園。若對佛教雕刻最感興趣請選本路線；最深度文化體驗請選民俗村路線；追求多樣性及室內行程請選光明路線。"},{"id":"q2","question":"門票含在費用內嗎？","answer":"是的——三處付費景點均已含括：水原華城城廓（成人1,000韓元）、華城行宮（成人1,500韓元）及臥牛精舍（免費入場）。星空圖書館亦對所有人免費開放。咖啡廳飲品、商場美食廣場餐費及任何紀念品消費須自行負擔。"},{"id":"q3","question":"含午餐嗎？","answer":"不含。午餐於星空水原商場美食廣場的自由活動時間內自理——選擇多樣、座位輕鬆，每人通常花費10,000至20,000韓元。圖書館與商場為第二站（約13:30抵達），時間安排自然地銜接上午的華城與下午的臥牛精舍。"},{"id":"q4","question":"臥牛精舍有何獨特之處？","answer":"這是一座非傳統寺院：1970年由北韓難民出身的金海根法師創建，以其個人蒐藏的逾3,000尊亞洲各地佛像為核心。鎮寺之寶為「佛頭」——一尊高8米的木雕佛頭，以「世界最大」列入金氏世界紀錄——以及「臥佛」，一尊以印尼杜松木雕刻而成、尺寸3米×12米的木雕臥佛。重達12噸的「統一之鐘」曾在1988年首爾奧運開幕時鳴響。免費入場，建議遊覽約75分鐘。"},{"id":"q5","question":"參觀寺院需要注意服裝嗎？","answer":"建議在臥牛精舍遮蓋雙肩——夏季穿著無袖上衣時請攜帶薄外層衣物。進入主殿時通常需摘帽。室外寺院範圍並無嚴格著裝規定，但穿著得體以示尊重深受歡迎。寺內階梯與坡道較多，建議穿著防滑舒適的步行鞋。"},{"id":"q6","question":"全天的步行量如何分配？","answer":"三處各具不同步行型態：華城城廓城牆段最為費力（坡度陡峭、城門處有台階，步行約1公里）；星空圖書館為全室內並設有電扶梯；臥牛精舍寺院範圍有台階與坡道（中等強度）。全天步行總計約3至4公里。舒適步行鞋不可或缺，尤其是走城牆與寺院步道時。"},{"id":"first-time","question":"這條路線適合首次造訪水原與龍仁的旅客嗎？","answer":"非常適合——對於希望在一天導覽行程中同時體驗一處聯合國教科文組織世界遺產、一處現代網美打卡空間與一座別具特色的佛教寺院的旅客來說，這是最優質的初訪首選之一。行程節奏均衡而不過於密集，各站地理位置相近（水原—龍仁廊道，相距約30分鐘車程）。提供弘大或明洞免費飯店接送，讓早晨出發毫無壓力。"},{"id":"walking","question":"步行難度大嗎？","answer":"中等強度步行。最費力的路段為華城城廓：約1公里的石造城牆步道，坡度陡峭、城門處有台階、地面高低不平——務必穿著防滑舒適的步行鞋。星空圖書館為平地室內步行，輕鬆無負擔。臥牛精舍有部分上坡路段與台階（中等強度）。全天步行總計約3至4公里。嬰兒車在城牆與寺院不易推行，在星空圖書館則完全適用。"},{"id":"family","question":"這條路線適合家庭出遊嗎？","answer":"適合——6歲以上孩童的家庭大多能舒適參與。嬰兒車在華城城牆與臥牛精舍較為不便，但星空圖書館設有電扶梯與電梯，完全適用嬰兒車。孩子們通常對臥牛精舍的巨型佛頭及逾3,000尊佛像深感震撼。在華城行宮租借韓服是深受家庭喜愛的拍照時刻（並可免費入場城廓）。"},{"id":"seniors","question":"年長者可以舒適地參加嗎？","answer":"對於能應付台階與不平地面的活躍年長者來說可以；行動不便的旅客則有所限制。華城城牆步道段最為吃力（陡坡、石階）；年長者可選擇較平緩的路段步行，跳過攀登瞭望台的部分。臥牛精舍有寺院台階，但主要佛像展區位於無障礙樓層。星空圖書館設有電扶梯與電梯，無障礙程度最佳，是整趟行程的「喘息站」。"},{"id":"children","question":"建議的最低參加年齡為何？","answer":"最適合約6歲以上的孩童。城廓城牆有台階及不平地面，臥牛精舍寺院有坡道，對幼齡兒童較為吃力。年齡較大的孩子表現良好——巨型佛頭與統一之鐘令人印象深刻，星空圖書館亦便於通行。嬰兒車在星空圖書館暢行無阻，但在城牆上不適用。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id 於執行時從 Supabase／環境變數解析，不屬於靜態 JSONB 的一部分。","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null}},"pickup_dropoff":{"departure":[{"order":1,"time":"08:30","name":"弘益大學站（4號出口）","type":"station","note":"首爾第一集合地點；請提前10分鐘抵達。","lat":37.55753,"lng":126.92447},{"order":2,"time":"09:00","name":"明洞站","type":"station","note":"首爾第二集合點。","lat":37.56099,"lng":126.98619}],"return":[{"order":1,"name":"明洞站","type":"station","note":"首爾標準下車點。","lat":37.56099,"lng":126.98619},{"order":2,"name":"弘益大學站","type":"station","note":"首爾標準下車點。","lat":37.55753,"lng":126.92447}],"notes":["返回時間視交通狀況而定，通常介於18:00至19:00之間。下車順序可能因營運效率略作調整。請於您所選集合點至少提前10分鐘抵達。本行程採固定集合點制，不提供飯店接送。"]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-suwon-hwaseong-waujeongsa-starfield","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"gyeonggi_south","vehicle_type":"minicoach","duration_hours":9,"region_tags":["seoul_capital","gyeonggi_suwon","gyeonggi_yongin","gyeonggi_south","seoul_day_trip"],"theme_tags":["unesco","fortress","buddhist_temple","contemporary_architecture","k_drama_filming_location","first_time_friendly","iconic_landmarks","heritage_plus_modern"],"poi_tags":["hwaseong_fortress","hwaseong_haenggung","starfield_library_suwon","waujeongsa_temple","yeonhwasan"],"pace_level":0.6,"walking_level":0.6,"scenic_level":0.85,"photo_level":1,"culture_level":1,"relax_level":0.8,"first_time_fit":0.7,"family_fit":0.85,"senior_fit":