  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"seoul-suwon-hwaseong-waujeongsa-starfield","locale":"es","product_id":"seoul-suwon-hwaseong-waujeongsa-starfield","seo":{"pageTitle":"Tour de un día por Suwon Hwaseong, Waujeongsa y Starfield | AtoC Korea","metaDescription":"Excursión de un día de 9 a 10 horas desde Seúl: Fortaleza de Suwon Hwaseong (Patrimonio UNESCO), Biblioteca Starfield Suwon y el Templo Waujeongsa con su gigantesco Buda al aire libre. Guía en inglés y traslados incluidos.","ogImage":"https://www.atockorea.com/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","primaryKeywords":["Tour de un día por Suwon Hwaseong","Templo Waujeongsa, Yongin","Biblioteca Starfield, Suwon","Tour del patrimonio Seúl–Suwon","Tour por la Fortaleza Hwaseong (Patrimonio UNESCO)"],"title":"Tour de un día por el patrimonio de Suwon Hwaseong, Templo Waujeongsa y Biblioteca Starfield | AtoC Korea"},"catalog_card":{"slug":"seoul-suwon-hwaseong-waujeongsa-starfield","title":"Suwon: Hwaseong, Waujeongsa y Starfield","subtitle":"Fortaleza UNESCO, templo de montaña y biblioteca viral: el pasado, el espíritu y el presente de Corea en una excursión de un día desde Seúl.","region":"Suwon y Yongin","duration":"9–10 horas","stopsCount":4,"rating":0,"reviewCount":0,"badges":["Patrimonio UNESCO","Excursión de un día: Patrimonio + Modernidad","Entradas incluidas"],"heroImage":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","thumbnail":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","priceLabel":"","shortCardDescription":"Una excursión en grupo reducido desde Seúl que recorre tres facetas contrastantes de Corea: la Fortaleza de Suwon Hwaseong, declarada Patrimonio UNESCO (arquitectura militar del siglo XVIII), la fotogénica Biblioteca Starfield Suwon (icono cultural contemporáneo) y el Templo Waujeongsa en Yongin (gigantesco Buda al aire libre y campana de piedra). Gran valor patrimonial con transporte y entradas incluidos.","tags":["unesco_heritage","heritage__modern_day_trip","admission_included"]},"headlineLine1":"Día del Patrimonio de Suwon","headlineLine2":"Hwaseong, Waujeongsa y Starfield","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null},"hero":{"imageUrl":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","imagePosition":"center 50%","tagline":"Desde una fortaleza UNESCO del siglo XVIII hasta una de las bibliotecas contemporáneas más fotografiadas de Corea, pasando por un tranquilo templo budista de montaña: tres facetas de Corea en un día perfectamente equilibrado.","pills":["Sitio UNESCO","Entradas incluidas","Traslados de ida y vuelta desde Seúl"],"meta":{"duration":"9–10 horas","region":"Suwon y Yongin","stops":"4 paradas","rating":0,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"Descripción general"},{"id":"itinerary","label":"Itinerario"},{"id":"details","label":"Detalles"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reseñas"}],"glanceItems":[{"icon":"camera","label":"Valor fotográfico","value":"Excelente","level":5},{"icon":"mountain","label":"Pintoresco","value":"Bueno","level":4},{"icon":"footprints","label":"Caminata","value":"Moderado","level":3},{"icon":"cloud-rain","label":"Seguridad bajo la lluvia","value":"Bueno","level":4},{"icon":"users","label":"Apto para familias","value":"Bueno","level":4},{"icon":"gauge","label":"Equilibrio","value":"Equilibrado","level":4}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Fortaleza Suwon Hwaseong","alt":"Fortaleza Suwon Hwaseong — gallery image 1","caption":"Fortaleza Suwon Hwaseong — photo 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 1","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 1"},{"id":3,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","location":"Templo Waujeongsa","alt":"Templo Waujeongsa — gallery image 1","caption":"Templo Waujeongsa — photo 1"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Fortaleza Suwon Hwaseong","alt":"Fortaleza Suwon Hwaseong — gallery image 2","caption":"Fortaleza Suwon Hwaseong — photo 2"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Fortaleza Suwon Hwaseong","alt":"Fortaleza Suwon Hwaseong — gallery image 3","caption":"Fortaleza Suwon Hwaseong — photo 3"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Fortaleza Suwon Hwaseong","alt":"Fortaleza Suwon Hwaseong — gallery image 4","caption":"Fortaleza Suwon Hwaseong — photo 4"},{"id":7,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Fortaleza Suwon Hwaseong","alt":"Fortaleza Suwon Hwaseong — gallery image 5","caption":"Fortaleza Suwon Hwaseong — photo 5"},{"id":8,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Fortaleza Suwon Hwaseong","alt":"Fortaleza Suwon Hwaseong — gallery image 6","caption":"Fortaleza Suwon Hwaseong — photo 6"},{"id":9,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 2","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 2"},{"id":10,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 3","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 3"},{"id":11,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 4","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 4"},{"id":12,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","location":"Templo Waujeongsa","alt":"Templo Waujeongsa — gallery image 2","caption":"Templo Waujeongsa — photo 2"},{"id":13,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","location":"Templo Waujeongsa","alt":"Templo Waujeongsa — gallery image 3","caption":"Templo Waujeongsa — photo 3"},{"id":14,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","location":"Templo Waujeongsa","alt":"Templo Waujeongsa — gallery image 4","caption":"Templo Waujeongsa — photo 4"},{"id":15,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","location":"Templo Waujeongsa","alt":"Templo Waujeongsa — gallery image 5","caption":"Templo Waujeongsa — photo 5"}],"itineraryStops":[{"number":1,"time":"≈ 10:00","duration":"75 min","name":"Fortaleza Hwaseong de Suwon","category":"Fortaleza UNESCO","description":"**Suwon Hwaseong (수원화성) — Patrimonio Mundial de la UNESCO desde 1997** — es la única ciudad amurallada de Corea conservada junto con su registro de construcción original en 10 volúmenes (Hwaseong Seongyeok Uigwe, inscrito por separado en el Registro de la Memoria del Mundo de la UNESCO en 2007). Construida **entre 1794 y 1796 en tan solo 2 años y 9 meses** bajo el reinado del Rey Jeongjo (정조, 22.º rey Joseon, r. \n\n1776-1800), Hwaseong fue el proyecto del rey para trasladar la capital Joseon de Hanyang (Seúl) a Suwon — y para honrar a su padre el Príncipe de la Corona Sado, quien fue encerrado vivo en un cofre de arroz por su propio padre, el Rey Yeongjo, en 1762. \n\nLa fortaleza fue diseñada por **Jeong Yak-yong (정약용, también conocido como Dasan)** — el principal académico-ingeniero de Joseon perteneciente a la escuela Silhak (aprendizaje práctico) — quien integró la arquitectura defensiva tradicional coreana con la teoría china de defensa ante asedios y la emergente ciencia occidental de fortificación. \n\nJeong Yak-yong inventó el **geojunggi (거중기)** — una grúa de poleas y motones basada en principios mecánicos occidentales — para elevar piedras pesadas durante la construcción; constituye el primer uso documentado de ingeniería moderna de estilo occidental en la construcción coreana. \n\nLa muralla completa de la fortaleza tiene **5,74 km de perímetro** y encierra 130 hectáreas con 41 estructuras estratégicas: 4 puertas principales (Janganmun al norte — la **puerta real existente más grande de Corea**, mayor que la Sungnyemun de Seúl; Paldalmun al sur; Hwaseomun al oeste; Changnyongmun al este), 4 torres angulares, 4 puestos de mando, 5 plataformas de vigilancia, 5 baterías de cañones, además de plataformas de tiro con arco, compuertas y torres de señales. \n\nEl paseo guiado de hoy recorre el **tramo más fotogénico de 1,2 km entre Janganmun (puerta principal norte) y Hwaseomun (puerta oeste, Tesoro Nacional N.º 403)** — la mayor densidad de estructuras militares conservadas, con ~25-30 minutos de caminata. Añada la visita al **Seojangdae (Puesto de Mando Oeste)** en lo alto del Monte Paldalsan para disfrutar del punto más elevado de la fortaleza y del puesto de mando estratégico del rey. \n\n**Hwahongmun (compuerta norte)** con sus 7 arcos sobre el Arroyo Suwoncheon es la estructura más fotografiada de la fortaleza — especialmente en primavera (flores de cerezo) y otoño (follaje). El grupo de visita recorre la muralla a pie; si el horario lo permite, hay disponible un tranvía turístico opcional **Hwaseong Trolley** (4.000 KRW adultos, ~30 min, ruta Yeonmudae→Paldalmun).","highlights":["**Patrimonio Mundial de la UNESCO desde 1997** — la única ciudad amurallada de Corea que conserva los registros originales de su construcción","Construida entre 1794 y 1796 en 2 años y 9 meses bajo el reinado del Rey Jeongjo (22.º rey Joseon)","Diseñada por Jeong Yak-yong combinando ciencia de fortificación coreana, china y occidental","Registro de construcción Hwaseong Seongyeok Uigwe — Memoria del Mundo de la UNESCO 2007","5,74 km de perímetro, 41 estructuras militares estratégicas","Puerta norte de Janganmun — **la puerta real existente más grande de Corea**","Paseo guiado de 1,2 km Janganmun → Hwaseomun (tramo con mayor densidad fotográfica)","Compuerta de 7 arcos Hwahongmun — la estructura más fotografiada","GRATIS para portadores de hanbok + último miércoles del mes + mayores de 65 años"],"timeUsed":["Bajada del autocar cerca de Janganmun (~5 min)","Breve orientación grupal en Janganmun (~5 min)","Caminata Janganmun → Hwaseomun pasando por Hwaseo Janggak (~25-30 min)","Tiempo para fotos + reagrupamiento en el vehículo (~10 min)","Tranvía turístico Hwaseong Yeolcha opcional Yeonmudae↔Paldalmun (~30 min solo ida; ₩4.000 adulto)"],"whyOnRoute":"El ancla UNESCO del recorrido — la única ciudad fortaleza amurallada que queda en Corea, construida entre 1794 y 1796 bajo el reinado del rey Jeongjo. El trayecto a pie Janganmun → Hwaseomun (~1,2 km) ofrece la mayor densidad de estructuras militares preservadas + la icónica compuerta de 7 arcos Hwahongmun en una parada de 75 minutos. Se eligió sobre el circuito completo de 5,74 km porque este tramo concentra la sección más fotografiada y de mayor riqueza histórica, dejando tiempo para las otras tres paradas patrimoniales del día. Hwaseong es también el **ancla obligatoria de cualquier excursión de un día a Suwon**, ya que rodea físicamente el palacio Haenggung, de modo que el bloque matinal en Suwon combina credenciales de Patrimonio Mundial UNESCO y la interioridad de una residencia real joseon antes de continuar hacia Starfield y el templo Waujeongsa. El tramo de muralla de 1,2 km Janganmun → Hwaseomun pasando por Hwaseo Janggak es el corredor de arquitectura militar preservada de mayor densidad de Corea (4 puertas principales + 5 puertas secretas + 4 compuertas + murallas construidas con el Geojunggi coexisten en 25-30 minutos de caminata).","visitBasics":{"hours":"Camino de la muralla abierto 24 horas (sin puertas); horario recomendado 09:00-18:00 verano / 09:00-17:00 invierno; horario nocturno mayo-oct mié-dom 18:00-21:30","closed":"Abierto todo el año (Tranvía Hwaseong cerrado los lunes)","admission":"Adultos 1.000 / Jóvenes 700 / Niños 500 KRW (GRATIS: niños ≤6 años, mayores de 65, portadores de hanbok, último miércoles del mes). Tranvía Hwaseong por separado 4.000 KRW","walking":"Moderado — la muralla tiene tramos empinados en Seojangdae; escaleras en las puertas; algunos tramos de difícil acceso para silla de ruedas"},"convenience":{"restroom":"En Janganmun, Hwaseomun, Paldalmun y Yeonmudae","parking":"Bajada del autocar en el aparcamiento de Janganmun; aparcamiento designado para autocares en Yeonmudae"},"smartNotes":{"photo":"**Hwahongmun (compuerta norte)** con 7 arcos sobre el arroyo Suwoncheon — la toma icónica, especialmente en primavera (flores de cerezo) y otoño (follaje). **Janganmun (la puerta real existente más grande de Corea)** a la hora dorada. **Seojangdae (puesto de mando oeste)** con puesta de sol sobre la montaña Paldalsan.","facilities":"Centro de Información al Visitante en Janganmun + Paldalmun + Plaza Hwaseong Haenggung. Señalización en inglés y coreano en todo el recinto. Alquiler de audioguía de Hwaseong disponible en Janganmun.","tip":"Use calzado cómodo — las piedras de la muralla son irregulares. Las tiendas de alquiler de hanbok en la Plaza Haenggung ofrecen entrada GRATUITA a la fortaleza y al palacio. **Evite el circuito completo de 5,74 km a menos que disponga de más de 2,5 horas** — el tramo Janganmun → Hwaseomun ofrece la mayor densidad patrimonial por metro."},"_poi_meta":{"poi_key":"hwaseong_fortress","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["UNESCO WHC","VisitKorea","KoreaToDo","Suwon CVB","UNESCO World Heritage Centre — Suwon Hwaseong (Criteria ii/iii inscription, 1997)","Korea Heritage Service / Cultural Heritage Administration (cha.go.kr — Hwaseong Fortress + Hwaseong Seongyeok Uigwe Memory of the World 2007)","Korea Tourism Organization (english.visitkorea.or.kr — Suwon Hwaseong Fortress official listing)","Suwon City Tourism (suwon.go.kr/tour — Hwaseong Yeolcha trolley + admission + opening hours)","Wikipedia (Hwaseong Fortress — Jeong Yak-yong + Geojunggi crane + 5.74 km perimeter + 41 structures)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/photo-002.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 1","alt":"Fortaleza Hwaseong de Suwon — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 2","alt":"Fortaleza Hwaseong de Suwon — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 3","alt":"Fortaleza Hwaseong de Suwon — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 4","alt":"Fortaleza Hwaseong de Suwon — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 5","alt":"Fortaleza Hwaseong de Suwon — gallery image 5"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Fortaleza Hwaseong de Suwon","caption":"Fortaleza Hwaseong de Suwon — photo 6","alt":"Fortaleza Hwaseong de Suwon — gallery image 6"}]},{"number":2,"time":"≈ 11:30","duration":"75 min","name":"Palacio Hwaseong Haenggung","category":"Palacio Real Destacado de Joseon","description":"**Hwaseong Haenggung (화성행궁) — el haenggung (palacio destacado) existente más grande de Corea** — fue construido entre 1789 y 1796 bajo el rey Jeongjo como parte del plan urbano unificado de la fortaleza Hwaseong. \n\nUn **haenggung** es una residencia real temporal/destacada utilizada por los reyes de Joseon durante viajes, refugio en tiempos de guerra o ceremonias especiales; el Hwaseong Haenggung supera en escala a los haenggung de Onyang, Bukhansan y Namhansan. El rey Jeongjo lo construyó principalmente para pernoctar durante sus visitas a la tumba de su padre ejecutado, el Príncipe de la Corona Sado (Hyeollyungwon, actualmente llamada Tumba Real Yungneung, a 4 km al sur) — una peregrinación que realizó **13 veces durante su reinado**. \n\nEl más famoso de estos viajes fue la **procesión real de 1795** con 6.000 acompañantes y 1.400 caballos, celebrando el 60.º cumpleaños de Lady Hyegyeong (la madre del rey y viuda de Sado). \n\nLa procesión de 1795 está documentada en el **Wonhaeng Eulmyo Jeongni Uigwe — inscrito en el Registro Memoria del Mundo de la UNESCO desde 2007**. El palacio constaba originalmente de **576 kan (habitaciones/crujías estructurales)** y funcionaba como una completa residencia real en miniatura con sala del trono (Bongsudang), sala secundaria (Naknamheon), aposentos residenciales (Janganheon), cocinas, oficinas militares y cuarteles de la guardia. \n\n**Destruido en gran parte durante el período colonial japonés** (1910-1945), cuando los japoneses convirtieron el recinto del palacio en el Hospital Provincial de Suwon y la Comisaría de Policía. \n\n**La restauración comenzó en 1996** siguiendo el registro de construcción original del Hwaseong Seongyeok Uigwe; la primera fase se completó en 2003 (Bongsudang, Naknamheon, Janganheon, Yuyeotaek) y la segunda fase en 2009 (cocina real Wuhwagwan, puerta de entrada Sinpung-nu). La restauración continúa hoy en día. \n\n**Nota histórica clave: Naknamheon (낙남헌) es el ÚNICO edificio que sobrevivió de la construcción original de 1796** — los japoneses lo convirtieron en oficinas de la Comisaría de Policía, pero no lo demolieron. Por tanto, es la única estructura auténtica original de madera y teja en el lugar; todos los demás edificios son reconstrucciones. \n\n**Ceremonia diaria de cambio de guardia real** en la puerta Sinpungnu — **martes a domingo a las 11:00 h** (según las condiciones meteorológicas), ~15 min, GRATIS. Recrea la ceremonia de la puerta del palacio de la era Joseon con guardias en uniformes rojo, azul y amarillo con tambores y cuernos tradicionales. \n\nEl horario del tour está programado para llegar a la ceremonia de las 11:00 h cuando el día de la semana lo permite. Filmado para el K-drama **''La joya del palacio'' (Daejanggeum, 2003)** — el icónico éxito de la era Joseon con un índice máximo de ~57% en MBC — convirtiéndolo en uno de los lugares sageuk más filmados de Corea.","highlights":["**El haenggung (palacio destacado) existente más grande de Corea** — originalmente 576 habitaciones","Construido entre 1789 y 1796 junto a la Fortaleza Hwaseong bajo el rey Jeongjo","El rey Jeongjo realizó 13 peregrinaciones reales aquí para honrar a su padre ejecutado, el Príncipe de la Corona Sado","**Naknamheon = ÚNICA estructura original de 1796 que se conserva** (las demás son reconstrucciones)","**Ceremonia de cambio de guardia real mar-dom a las 11:00 h en la puerta Sinpungnu (GRATIS, ~15 min)**","Procesión Real de 1795 documentada en la Memoria del Mundo de la UNESCO","Lugar de filmación del k-drama ''La Joya del Palacio'' (2003 en MBC, índice máximo ~57%)","GRATIS para personas con hanbok + mayores de 65 años + niños de 6 años o menos","**Naknamheon (낙남헌) es el ÚNICO edificio que sobrevive de la construcción original de 1796** — las autoridades de la era colonial japonesa lo convirtieron en oficinas de la Comisaría de Policía, pero no lo demolieron; todas las demás estructuras del Haenggung visibles hoy en día son reconstrucciones posteriores a 1996 basadas en el Hwaseong Seongyeok Uigwe (Memoria del Mundo de la UNESCO desde 2007)"],"timeUsed":["A 5 minutos a pie de la Fortaleza Hwaseong (zona de Hwaseomun)","Llegue a tiempo para la **Ceremonia del Cambio de Guardia Real a las 11:00** en Sinpungnu (~15 min)","Recorrido por el Salón del Trono Bongsudang + Naknamheon + Janganheon (~30 min)","Tiempo para fotos + reagrupamiento en el vehículo (~15 min)","Ceremonia opcional del Cambio de Guardia Real en la Puerta Sinpungnu (mar-dom 11:00, ~15 min, GRATIS — sujeto a condiciones meteorológicas)"],"whyOnRoute":"Se complementa de forma natural con la muralla de la fortaleza — la residencia real temporal está DENTRO del mismo sitio de la UNESCO, a solo 5 minutos. El haenggung más grande de Corea (originalmente 576 habitaciones), con **Naknamheon como la única estructura auténtica original** (las demás son reconstrucciones posteriores a 1996 basadas en el Hwaseong Uigwe). Programe la llegada para la Ceremonia del Cambio de Guardia Real (mar-dom 11:00), que es GRATUITA y dura ~15 min — uno de los atractivos de experiencia cultural gratuita más destacados del catálogo. Visitar el Haenggung inmediatamente después de las murallas de la fortaleza convierte una lección abstracta de arquitectura militar en una experiencia espacial real de la Corea joseoniana — el mismo salón del trono Bongsudang donde el Rey Jeongjo recibió a sus funcionarios en 1795 también acogió el espléndido banquete del 60.º cumpleaños de su madre, Lady Hyegyeong (representado en los rollos de pintura cortesana Banchado conservados en el Uigwe). Se vende una **entrada combinada Fortaleza + Haenggung** por 3.500 KRW (frente a 2.500 KRW por separado) — un atractivo tangible de valor añadido para la parada en Suwon. La Ceremonia del Cambio de Guardia Real en la Puerta Sinpungnu (mar-dom 11:00, ~15 min, GRATIS) está programada para coincidir con la mayoría de los horarios de llegada a Suwon en las excursiones de un día desde Seúl.","visitBasics":{"hours":"09:00-18:00 (última entrada 17:30); horario nocturno de verano mayo-oct 18:00-21:00","closed":"Abierto todo el año","admission":"Adulto 1.500 / Joven 1.000 / Niño 700 KRW. Entrada combinada Fortaleza + Haenggung 3.500 KRW. GRATIS para personas con hanbok, mayores de 65 años, niños de 6 años o menos","walking":"Fácil — los terrenos del palacio son mayormente planos con algunos escalones entre los patios"},"convenience":{"restroom":"En la entrada principal, cerca de Bongsudang y en la Plaza Haenggung","parking":"Aparcamiento público de Hwaseong Haenggung; aparcamientos de pago en la Plaza Haenggung"},"smartNotes":{"photo":"**Salón Principal Bongsudang** — la icónica toma del salón del trono. **Naknamheon** — la única estructura original de 1796 (la fotografía más auténtica desde el punto de vista histórico). **Ceremonia del Cambio de Guardia Real en la Puerta Sinpungnu** (mar-dom 11:00). Personas con hanbok frente a Sinpungnu — el punto más popular de Suwon para fotografiarse con hanbok.","facilities":"Centro de información para visitantes, aseos, tienda de regalos. Cafeterías y alquiler de hanbok en la Plaza Haenggung (15.000-20.000 KRW por 4 horas). Restaurantes de Suwon Tongdak (pollo asado entero) a 5 minutos a pie.","tip":"**Programe la llegada para la Ceremonia del Cambio de Guardia Real a las 11:00 de mar a dom (GRATIS)**. El alquiler de hanbok incluye entrada GRATUITA tanto a la Fortaleza como al Haenggung. **Naknamheon es EL punto históricamente más importante** — la única estructura no reconstruida, que sobrevivió a la demolición durante la época colonial japonesa. Evite los lunes — la Ceremonia del Cambio de Guardia Real se celebra únicamente de mar a dom."},"_poi_meta":{"poi_key":"hwaseong_haenggung","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Suwon CVB","Korea Tourism Organization (english.visitkorea.or.kr — Hwaseong Haenggung official listing)","Cultural Heritage Administration / Korea Heritage Service (cha.go.kr — Hwaseong Haenggung Historic Site No. 478)","Suwon City Tourism (suwon.go.kr/tour — Royal Guard Changing Ceremony + Mu-ye 24-gi schedule)","Wikipedia (Hwaseong Haenggung — Naknamheon-only-original-structure + 576-kan scale)","Visit Suwon CVB (visitsuwon.org — Suwon Pass combined ticket + Haenggung Square facilities)"]},"image":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","images":["/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","/images/tours/suwon-hwaseong/photo-002.webp"],"imageCredits":[{"url":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","source":"atoc-korea"},{"url":"/images/tours/suwon-hwaseong/photo-002.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/suwon-hwaseong/kakaotalk-20260510-222949305.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 1","alt":"Palacio Hwaseong Haenggung — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-00-57.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 2","alt":"Palacio Hwaseong Haenggung — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-43.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 3","alt":"Palacio Hwaseong Haenggung — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-09-58.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 4","alt":"Palacio Hwaseong Haenggung — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/suwon-hwaseong/chatgpt-image-2026-5-11-01-12-24.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 5","alt":"Palacio Hwaseong Haenggung — gallery image 5"},{"id":6,"type":"photo","src":"/images/tours/suwon-hwaseong/photo-002.webp","location":"Palacio Hwaseong Haenggung","caption":"Palacio Hwaseong Haenggung — photo 6","alt":"Palacio Hwaseong Haenggung — gallery image 6"}]},{"number":3,"time":"≈ 13:30","duration":"90 min","name":"Biblioteca y Centro Comercial Starfield Suwon","category":"Hito Cultural Moderno + Almuerzo","description":"**Biblioteca Starfield Suwon (별마당 도서관 수원)** — ubicada dentro de **Starfield Suwon, el emblemático centro comercial Starfield de ''segunda generación'' de Shinsegae inaugurado el 26 de enero de 2024** como el quinto centro comercial Starfield de Shinsegae Property; la inversión total superó 1 billón de KRW (~750 millones de USD); ~334,000 m² de superficie bruta total, convirtiéndolo en el 2.º centro comercial cubierto más grande de Corea después de Starfield Hanam. \n\nDiseñada en colaboración con **BCHO Partners (Cho Byoung-soo)** — la firma coreana responsable de la Biblioteca Starfield COEX original (2017) — la biblioteca de Suwon representa la iteración de segunda generación con **estanterías que alcanzan hasta 22 metros de altura**, entre las estructuras de estanterías cilíndricas más altas en cualquier espacio público de Corea. \n\nLa biblioteca abarca **4 plantas (atrio abierto del 1F al 4F)** con aproximadamente **70,000 libros y revistas**, incluyendo publicaciones coreanas e internacionales, publicaciones periódicas, libros de arte y una sección dedicada a literatura infantil en el 4F. \n\n**GRATUITA y abierta al público** — sin tarjeta de biblioteca, sin entrada, accesible en todo el horario del centro comercial. Características destacadas: **Sala de Escucha de Vinilos** con selección de indie coreano + jazz/rock clásico en vinilo; **exposición de arte con rotación mensual** en el espacio del atrio; e **instalación estacional de flores de cerezo en el atrio central (marzo-abril)** con miles de pétalos LED rosas — uno de los rincones más fotografiados de Suwon en primavera. \n\n**El almuerzo está incluido en esta parada de 90 min** en el **patio de comidas Eatopia (B1F)** con más de 30 restaurantes que van desde cocina coreana de servicio rápido (5,000-10,000 KRW) hasta opciones coreanas e internacionales de gama media (15,000-25,000 KRW). Barbacoa coreana, bibimbap, kalguksu, mandu, tonkatsu japonés, fusión coreano-mexicana (Ko-Mex), hamburguesas australianas Mountain Bus, pho, empanadillas — amplia variedad de cocinas. \n\nInstalaciones adicionales del centro comercial: **Parque acuático Aquafield Suwon + spa coreano (B1-2F)** con entrada separada de pago ~25,000-35,000 KRW; **Toy Kingdom (4F, la mayor juguetería de Corea)**; **sistema de doble cine CGV/MEGABOX**. \n\n**Autobús lanzadera gratuito de Starfield** desde la Salida 4 de la Estación de Suwon cada 10-15 min (~10 min de trayecto) — la opción más cómoda desde el transporte público. Visitantes anuales: **~28 millones en el primer año (2024)** — entre los 3 destinos comerciales más visitados de Corea.","highlights":["**Centro comercial Starfield de segunda generación y buque insignia de Shinsegae — inaugurado el 26 de enero de 2024**","Diseñado por BCHO Partners (también diseñó la Biblioteca Starfield COEX original en 2017)","**Biblioteca de 4 plantas con estanterías de 22 metros** — entre las estanterías cilíndricas más altas de Corea","~70,000 libros + revistas de acceso GRATUITO","Sala de Escucha de Discos de Vinilo","Instalación de pétalos LED de flores de cerezo (marzo-abril)","**Almuerzo incluido en la parada** — patio de comidas Eatopia B1F con más de 30 restaurantes","Parque acuático Aquafield + spa coreano, Toy Kingdom (el más grande de Corea), cine CGV+MEGABOX","Lanzadera gratuita de Starfield desde la Salida 4 de la Estación de Suwon (~10 min)","~28 millones de visitantes en el primer año (2024)"],"timeUsed":["30 min en autocar desde la Fortaleza Hwaseong hasta Starfield Suwon","Almuerzo en el patio de comidas Eatopia (~30-45 min)","Recorrido por la biblioteca y el atrio + tiempo para fotos (~30-40 min)","Compras breves + reagrupación en el autocar (~10-15 min)","Almuerzo opcional en el food hall Eatopia (B1F, más de 30 restaurantes coreanos e internacionales; ~₩10,000-25,000 por persona; 45-60 min)"],"whyOnRoute":"El contrapeso de la ''Corea moderna'' tras el ancla patrimonial UNESCO de la mañana. La **parada combinada de biblioteca + almuerzo** es el diseño del Tour 3 — aprovechando el food hall Eatopia para el almuerzo (eliminando una parada de restaurante separada). La biblioteca + estanterías de 22 metros es el escaparate arquitectónico, y el entorno completamente interior protege contra cualquier riesgo meteorológico a mediodía. **El almuerzo se realiza en el food hall Eatopia de Starfield** — la parada combinada de 90 min encaja de forma natural en el día compacto de 4 paradas. Para esta parada de pivote a mediodía, la Biblioteca Starfield funciona como el **respiro arquitectónico y de ocio** entre el intenso contenido histórico-arquitectónico de Hwaseong y el intrincado contenido religioso-sincrético de Waujeongsa — las estanterías del atrio de 22 m ofrecen satisfacción de parada fotográfica con **entrada GRATUITA**, mientras que el centro comercial circundante (más de 600 marcas minoristas, food hall Eatopia, parque acuático Aquafield) permite una logística flexible de almuerzo + baños + café + pausa de compras que ni Hwaseong ni Waujeongsa ofrecen directamente.","visitBasics":{"hours":"Centro comercial 10:00-22:00; biblioteca accesible durante todo el horario del centro comercial","closed":"1-2 días de cierre mensual (generalmente lunes — verificar en línea)","admission":"Biblioteca GRATUITA; food hall Eatopia pago por consumo (almuerzo ~5,000-25,000 KRW por persona)","walking":"Fácil — escaleras mecánicas y ascensores entre todas las plantas; accesible para sillas de ruedas y cochecitos en todo el recinto"},"convenience":{"restroom":"Múltiples aseos en cada planta; estaciones adaptadas para familias","parking":"Aparcamiento subterráneo ~5,000 plazas; primeras 3 horas GRATUITAS con compra en el centro de 30,000 KRW o más; zona de autobuses para grupos"},"smartNotes":{"photo":"**Atrio central de la biblioteca con estanterías de 22 metros** visto desde la galería de la 4ª planta mirando hacia abajo. **Salón de Discos de Vinilo** para estética retro. **Instalación de flores de cerezo en el atrio (marzo-abril)** — foto viral de temporada. Árbol de Navidad (diciembre). Sección infantil en la 4ª planta para fotos familiares.","facilities":"Food hall Eatopia B1F (más de 30 restaurantes 5,000-40,000 KRW), Toy Kingdom 4ª planta, parque acuático Aquafield B1-2F, cines CGV + MEGABOX, WiFi gratuito, atención al cliente multilingüe, mostradores de devolución de impuestos en las principales tiendas.","tip":"**La biblioteca es GRATUITA** durante todo el horario del centro comercial. **Estanterías de 22 metros = las estanterías de biblioteca más altas de Corea** (mencionar a los visitantes para mayor impacto). **La instalación de flores de cerezo de marzo a abril** es el imprescindible de temporada. **Food hall Eatopia para el almuerzo** — no se requiere reserva previa; visitar entre las 13:00-13:30 para evitar el pico del almuerzo coreano. Evitar las tardes de los sábados (máxima densidad de visitantes). Verificar las fechas de cierre mensual de Starfield en línea antes de la visita."},"_poi_meta":{"poi_key":"starfield_library_suwon","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["Starfield official","VisitKorea","Shinsegae press","BCHO Partners","Starfield Suwon official (starfield.co.kr/suwon — opening date 2024-01-26 + library 4F-7F + free admission)","Shinsegae Property press release (Jan 2024 grand opening + 5th Starfield mall + 2nd-generation flagship concept)","Korea Tourism Organization (english.visitkorea.or.kr — Starfield Library Suwon listing)","ArchDaily — BCHO Partners (Cho Byoung-soo) Starfield Suwon design review","Wikipedia (Starfield Suwon — 22m bookshelves + Douglas Coupland ''The Planets'' rooftop installation)"]},"image":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","images":["/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp"],"imageCredits":[{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","source":"atoc-korea"},{"url":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-18.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 1","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-07-38.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 2","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-55.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 3","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/starfield-library-suwon/chatgpt-image-2026-5-10-12-22-58.webp","location":"Biblioteca y Centro Comercial Starfield Suwon","caption":"Biblioteca y Centro Comercial Starfield Suwon — photo 4","alt":"Biblioteca y Centro Comercial Starfield Suwon — gallery image 4"}]},{"number":4,"time":"≈ 15:30","duration":"75 min","name":"Templo Waujeongsa","category":"Templo Budista (Ecléctico Moderno)","description":"**Templo Waujeongsa (와우정사)** — **fundado en 1970 por el monje Kim Hae Geun (김해근)** como refugio para monjes budistas norcoreanos separados de sus templos de origen tras la división de la península durante la Guerra de Corea (1950-1953). \n\nEl templo fue establecido originalmente como ''Cheonsa-bul'' (literalmente ''Templo de los Mil y Un Budas'') en homenaje al panteón budista de 33 deidades multiplicado en plegarias por la reunificación coreana. \n\n**Wau (와우, 臥牛)** = ''vaca reclinada'' — en referencia a la topografía del cercano Yeonhwasan (Monte de la Flor de Loto), que semeja una vaca recostada vista desde la distancia. \n\n**Jeong-sa (정사, 精舍)** = ''templo'' (ermita budista). El nombre completo se traduce, por tanto, como ''Templo de la Vaca Reclinada.'' **Uno de los templos budistas arquitectónicamente más singulares de Corea** — diseño sincrético ecléctico que incorpora elementos de tradiciones budistas de India, Sri Lanka, Tailandia, Myanmar (Birmania), Tíbet, China y Corea. \n\nAlberga ~3.000 estatuas budistas de diversos países budistas asiáticos distribuidas por los terrenos. **Este NO es un templo típico coreano de la era Joseon**, sino un templo de oración por la reunificación construido en 1970 — diferenciarlo para los visitantes. Características distintivas: el **Buda reclinado de madera de 12 metros de largo × 3 metros de alto (Wabul)** tallado de un único árbol de enebro indonesio — el **Buda reclinado de madera más grande del mundo** (Récord Guinness); la **escultura de cabeza de Buda al aire libre de 8 metros (Buldu, 불두)** en la entrada del templo, de bronce con recubrimiento de pan de oro, una de las esculturas de cabeza de Buda más altas de Corea; el **Buda de jade sentado de 3 metros** tallado en jade blanco importado de Myanmar — el Buda de jade más grande de Corea; y el **Salón Principal Bonzejeon** que alberga un Buda de latón de 8 metros importado de Myanmar. \n\n**Campana de la Unificación (통일대종)** — una campana de bronce de 12 toneladas tañida en la apertura de los Juegos Olímpicos de Seúl 1988, dedicada a la reunificación coreana; los visitantes pueden tocarla (se aceptan donaciones). \n\n**Pagoda Indravarna (인드라바르나탑)** de estilo esrilanqués con exterior de yeso blanco. **Stupa que contiene reliquias de Buda (sarira) donadas por las Órdenes Budistas de Sri Lanka, Tailandia y Myanmar** — un singular obsequio diplomático interbudista. \n\n**Entrada GRATUITA**. **Programa Templestay** disponible (práctica nocturna guiada por monjes, práctica tradicional de 108 reverencias, meditación Seon, cocina del templo budista, ceremonia tradicional del té — reservas a través de templestay.com, ~70.000-90.000 KRW por noche). \n\n**Mejores temporadas fotográficas: flores de cerezo en primavera (abril) y follaje otoñal (octubre-noviembre)** — ginkgos dorados y arces rojos enmarcan los edificios del templo. \n\nLos terrenos del templo ocupan una ladera con escaleras entre los pabellones; ~500 m a pie con desnivel positivo.","highlights":["**Fundado en 1970 por el monje Kim Hae Geun como templo de oración por la reunificación coreana**","Diseño sincrético ecléctico — budismo panasiático (India, Sri Lanka, Tailandia, Myanmar, Tíbet, China, Corea)","~3.000 estatuas budistas de diversos países budistas asiáticos","**Buda reclinado de madera de 12 metros de largo × 3 metros de alto = EL MÁS GRANDE DEL MUNDO** (enebro indonesio, Récord Guinness)","**Escultura de cabeza de Buda al aire libre de 8 metros** en la entrada del templo — la más alta de Corea","**Buda de jade de 3 metros** = el más grande de Corea","Campana de la Unificación = campana de bronce de 12 toneladas tañida en la apertura de los Juegos Olímpicos de Seúl 1988, por la reunificación coreana","Reliquias de Buda (sarira) donadas por las Órdenes de Sri Lanka/Tailandia/Myanmar","**Entrada GRATUITA** + programa Templestay disponible","Flores de cerezo en primavera / follaje otoñal — temporada fotográfica óptima"],"timeUsed":["30 minutos en autobús desde Starfield Suwon hasta Waujeongsa en Yongin","Orientación grupal breve en la entrada del templo (~5 min)","Recorrido autoguiado: cabeza de Buda → salones principales → Buda reclinado → campana → pagoda (~50-60 min)","Reagrupamiento en el autobús (~10 min)","Opcional: toque de la Campana de la Unificación (12 toneladas de bronce, tañida en la apertura de los Juegos Olímpicos de Seúl 1988) con deseo de reunificación (se aceptan donaciones; ~10 min)"],"whyOnRoute":"Final de montaña-templo del Tour 3 — contraste espiritual tranquilo frente a la arquitectura militar de Hwaseong y la modernidad comercial de Starfield. **Posicionamiento diferenciado respecto a los templos coreanos típicos**: Waujeongsa es un templo budista ecléctico panasiático sincrético construido en 1970 (NO un templo tradicional de la era Joseon) — lo que lo convierte en una experiencia visualmente más impactante y accesible al turismo que los templos tradicionales enclavados en la montaña. La **entrada GRATUITA** mantiene el presupuesto del tour ajustado. El entorno del Yeonhwasan de Yongin + ~30 min en coche desde Starfield lo posiciona como una extensión coherente hacia el oeste del circuito del día antes del regreso vespertino. Cerrar el día en Waujeongsa desplaza el registro del Joseon-secular (Hwaseong) y lo comercial del siglo XXI (Starfield) al **budista-sincrético del siglo XX** — el sincretismo ecléctico del templo de oración por la reunificación fundado en 1970 (Buda reclinado de sándalo indio + pagoda Indravarna de estilo esrilanqués + Budas de latón y jade blanco importados de Birmania + reliquias budistas donadas por Sri Lanka/Tailandia/Myanmar) no se parece a ningún templo coreano más antiguo, convirtiéndolo en un ancla contemplativa idónea para las horas vespertinas antes del regreso a Seúl. **La entrada es GRATUITA** (se aceptan donaciones en el salón principal). En coche: ~50-60 min desde Starfield Suwon en dirección a Yongin. Mejor temporada fotográfica: **flores de cerezo en primavera (abril-mayo)** o **follaje de ginkgo + arce en otoño (octubre-noviembre) enmarcando los edificios del templo**.","visitBasics":{"hours":"Diario 06:00-19:00 (salas de visitantes generalmente 09:00-18:00)","closed":"Abierto todo el año","admission":"**GRATIS** (se aceptan donaciones); Templestay con pernocta ~70,000-90,000 KRW","walking":"Moderado — el recinto del templo se encuentra en una ladera con escaleras entre los pabellones; ~500 m de caminata con desnivel"},"convenience":{"restroom":"Cerca del pabellón principal y del área de información para visitantes","parking":"Estacionamiento gratuito en el área de entrada al templo; se admiten autobuses turísticos"},"smartNotes":{"photo":"**Cabeza de Buda de 8 metros (Buldu)** en la entrada — la fotografía icónica de Waujeongsa, especialmente con el follaje otoñal de fondo. **Buda reclinado de madera de 3 metros** dentro del pabellón principal (el Buda reclinado de madera más grande del mundo). **Pagoda Indravarna** de estilo esrilanqués. Estatuas de Buda de toda Asia en los patios. **Flores de cerezo (abril) o follaje otoñal (octubre-noviembre)** convierten el templo en un destino para fotógrafos.","facilities":"Centro de información para visitantes, oficina de registro de Templestay, túnicas de monje a la venta, tienda de cuentas de oración y artículos budistas, cantina de cocina vegetariana del templo (almuerzo ~10,000 KRW). Senderos de senderismo en el monte Yeonhwasan detrás del templo (circuito de 4 km, ~1,5 h).","tip":"**Entrada GRATUITA** — valor excepcional en comparación con otros grandes templos coreanos. **Distinto de los templos tradicionales** — explicar a los visitantes que NO es un templo de la era Joseon, sino un **templo ecléctico panasiático de oración por la reunificación, construido en 1970**. **Mejores temporadas fotográficas**: flores de cerezo en primavera (abril) o follaje otoñal (finales de octubre a principios de noviembre). Vestir ropa modesta (hombros y rodillas cubiertos). La cabeza de Buda de 8 metros en la entrada es la foto icónica por consenso universal. El **programa Templestay** es una experiencia única para los visitantes con tiempo adicional — se requiere reserva previa en templestay.com."},"_poi_meta":{"poi_key":"waujeongsa_temple","verified":true,"match":"single_poi","kb_version":"1.28","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Visit Yongin","Templestay Korea","Korea Tourism Organization (english.visitkorea.or.kr — Waujeongsa Temple official listing)","Visit Yongin Tourism (yongin.go.kr/tour — Master Haedeung 1970 founding + reunification prayer temple)","Templestay Korea (templestay.com — Waujeongsa overnight program + 108-bow practice + sachal eumsik cuisine)","Wikipedia (Waujeongsa — pan-Asian Buddhist syncretism + Indravarna pagoda + Taepyeongjong 8-ton bell)","Korea Buddhism Yeonhwasan/Lotus-Mountain regional guide (Waujeongsa 와우 = ''reclining cow'' + sandalwood reclining Buddha origin)"]},"image":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","images":["/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp"],"imageCredits":[{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","source":"atoc-korea"},{"url":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-40.webp","location":"Templo Waujeongsa","caption":"Templo Waujeongsa — photo 1","alt":"Templo Waujeongsa — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-03-50.webp","location":"Templo Waujeongsa","caption":"Templo Waujeongsa — photo 2","alt":"Templo Waujeongsa — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-03.webp","location":"Templo Waujeongsa","caption":"Templo Waujeongsa — photo 3","alt":"Templo Waujeongsa — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-07-11-3.webp","location":"Templo Waujeongsa","caption":"Templo Waujeongsa — photo 4","alt":"Templo Waujeongsa — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/waujeongsa/chatgpt-image-2026-5-10-12-14-33.webp","location":"Templo Waujeongsa","caption":"Templo Waujeongsa — photo 5","alt":"Templo Waujeongsa — gallery image 5"}]}],"routeFlowStops":[{"name":"Hwaseong","type":"origin","theme":"Pasado UNESCO"},{"name":"Palacio Hwaseong Haenggung","type":"primary","theme":"Palacio Patrimonial"},{"name":"Biblioteca Starfield","type":"primary","theme":"Corea Moderna"},{"name":"Almuerzo","type":"meal","theme":"Pausa"},{"name":"Waujeongsa","type":"return","theme":"Cierre Espiritual"}],"routePhases":[{"phase":"Patrimonio de la UNESCO","duration":"Paradas 1","description":"Mañana: Patrimonio de la UNESCO"},{"phase":"Biblioteca y Almuerzo","duration":"Paradas 2–3","description":"Mediodía: Biblioteca y Almuerzo"},{"phase":"Final en el Templo de la Montaña","duration":"Paradas 4","description":"Tarde: Final en el Templo de la Montaña"}],"routeShapeIntro":{"title":"Cómo transcurre este día","subtitle":"Recogida en uno de los dos puntos de encuentro en Seúl (normalmente la estación de la Universidad Hongik o Myeongdong) alrededor de las 09:00, seguida del patrimonio de la UNESCO por la mañana, la biblioteca contemporánea y el almuerzo al mediodía, y un tranquilo cierre en un templo en Yongin. Regreso a Seúl entre las 18:00 y las 19:00."},"whyTourWorks":{"bestFor":["Visitantes que llegan por primera vez a Corea y desean combinar patrimonio histórico y modernidad en un solo día","Viajeros con interés por la historia y entusiastas del patrimonio de la UNESCO","Fotógrafos (murallas de Hwaseong, atrio de Starfield, estatuas de Buda)","Parejas y familias adultas que buscan un día equilibrado en lugar de activo","Viajeros que desean un formato de grupo pequeño con entrada incluida"],"routeLogicSections":[{"title":"Por qué esta ruta Suwon-Yongin funciona","icon":"landmark","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Tres épocas en un solo día","detail":"La arquitectura UNESCO de la era Joseon, el estilo de vida coreano contemporáneo y un templo budista de montaña abarcan tres facetas muy distintas de la cultura coreana sin necesidad de volver sobre los mismos pasos."},{"label":"Geografía compacta","detail":"Hwaseong, Starfield Suwon y Waujeongsa se encuentran todos a menos de 30 minutos en coche entre sí, al sur de Seúl, por lo que el tiempo de desplazamiento se mantiene manejable."},{"label":"Mayor valor que un viaje exclusivo a Hwaseong","detail":"Añadir Starfield y el templo convierte una visita de atracción única en una excursión de día más completa sin un gran incremento de precio."}]},{"title":"Cómo se siente realmente el esfuerzo al caminar","icon":"footprints","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Hwaseong es la sección más activa","detail":"El recorrido por la muralla es la principal exigencia física de la ruta, con escalones de piedra y superficies irregulares. La mayoría de los viajeros lo afrontan bien con calzado adecuado."},{"label":"Starfield es tiempo de descanso","detail":"La biblioteca y la pausa para el almuerzo implican esencialmente caminar en interiores y tiempo sentado, lo que ofrece a la ruta una recuperación útil a mitad del día."},{"label":"Waujeongsa es moderado","detail":"Los terrenos del templo incluyen algo de caminata cuesta arriba y escaleras, pero cada tramo es corto y la estatua principal del Buda es accesible desde la entrada."}]},{"title":"Notas sobre el clima","icon":"cloud-rain","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"Hwaseong es la parada más sensible al clima","detail":"La lluvia intensa o la nieve hacen que el paseo por la muralla sea menos cómodo; el palacio interior de Haenggung es una buena alternativa en días de mal tiempo."},{"label":"Starfield es un refugio completo ante el clima","detail":"La biblioteca y el centro comercial son completamente interiores, por lo que esta parada resulta un ancla muy útil para días lluviosos."},{"label":"La humedad del verano afecta el día","detail":"Los muros de la fortaleza y los terrenos del templo están al aire libre; lleva agua y protección solar entre junio y agosto."}]}],"lessIdealFor":["Viajeros que desean un día dedicado principalmente a las compras en el centro comercial","Visitantes a quienes no les gusta caminar sobre muros de piedra o caminos de templos","Cualquier persona que necesite un día con ritmo completamente fijo y sin caminatas","Viajeros que desean visitar los palacios centrales de Seúl (este recorrido se realiza fuera de Seúl)"]},"practicalAccordionItems":[{"id":"pickup","title":"Recogida y regreso","preview":"Dos puntos de encuentro en Seúl; salida aproximada a las 09:00","content":["Recogida habitualmente desde la Estación de la Universidad Hongik (Salida 4) y la Estación de Myeongdong","Salida generalmente entre las 08:30 y las 09:00 desde el primer punto de encuentro","Por favor, llega al menos 10 minutos antes al punto de encuentro seleccionado","Regreso a los mismos puntos de encuentro en Seúl","Regreso estimado entre las 18:00 y las 19:00 según el tráfico y los retrasos del domingo","Este es un formato de grupo con ruta fija, sin recogida en hotel; los viajeros deben llegar al punto de encuentro por sus propios medios"]},{"id":"walking","title":"Caminata y terreno","preview":"Moderado; el muro de Hwaseong es la sección física principal","content":["Fortaleza Hwaseong: escalones de piedra a lo largo del paseo por el muro y en las puertas principales; superficies históricas irregulares","Biblioteca y Centro Comercial Starfield: caminata interior sencilla sobre pisos planos","Templo Waujeongsa: moderado, con algunos senderos en pendiente y escaleras","Se recomiendan zapatos cómodos para caminar con buen agarre","El uso de cochecito es posible únicamente en Starfield; los muros de Hwaseong y Waujeongsa no son aptos para cochecitos"]},{"id":"weather","title":"Política meteorológica","preview":"La lluvia ligera es manejable; la lluvia intensa reduce el recorrido por la fortaleza","content":["Lluvia ligera: el recorrido generalmente continúa con ajustes normales","Lluvia intensa o nieve: el paseo por el muro de Hwaseong puede acortarse en favor del Palacio Hwaseong Haenggung","Starfield es una parada completamente cubierta y funciona como refugio en días de mal tiempo","Waujeongsa está parcialmente al aire libre; las operaciones del templo continúan con lluvia ligera"]},{"id":"wear","title":"Qué ponerse y qué llevar","preview":"Calzado para caminar, ropa modesta para el templo, capas de ropa","content":["Calzado cómodo para caminar con buen agarre (imprescindible para Hwaseong y Waujeongsa)","Ropa modesta para la visita al templo (se recomienda llevar los hombros cubiertos)","Capas ligeras para las temperaturas cambiantes entre los muros al aire libre y los espacios interiores","Protección solar y agua en verano","Cámara o teléfono con gran angular para las fotos de la Biblioteca Starfield"]},{"id":"included","title":"Qué está incluido","preview":"Guía, transporte y entrada incluidos; el almuerzo se paga directamente","variant":"incluido","content":["Guía profesional de habla inglesa","Transporte de ida y vuelta desde Seúl (vehículo para grupos pequeños)","Todas las tarifas de entrada (Hwaseong, Hwaseong Haenggung, Starfield es gratuito, Waujeongsa)","El almuerzo no está incluido; pague directamente en los restaurantes del centro comercial Starfield","Las compras personales no están incluidas","Las compras opcionales en cafeterías no están incluidas","Las propinas para el guía son opcionales"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"Integración de clima en tiempo real"},"tomorrow":{"temp":"—","label":"Actualizado diariamente"}},"seasonalVariations":[{"season":"Primavera","title":"Temporada de flor de cerezo","description":"Los cerezos en flor bordean el muro de Hwaseong a principios de abril, lo que convierte esta época en una de las mejores temporadas fotográficas de la ruta.","icon":"flower"},{"season":"Verano","title":"Exuberante pero húmedo","description":"Terrenos del templo exuberantes y días más largos, pero la humedad y el calor acumulado en los muros hacen que el tramo matutino resulte más exigente.","icon":"sun"},{"season":"Otoño","title":"La mejor temporada en general","description":"Visibilidad nítida y follaje a lo largo de la muralla de Hwaseong y Yeonhwasan; una de las temporadas más completas para esta ruta.","icon":"leaf"},{"season":"Invierno","title":"Tranquilo y dramático","description":"Recintos del templo en calma y murallas de la fortaleza imponentes; frío pero visualmente gratificante. Abrígate bien, ya que el paseo por la muralla está muy expuesto.","icon":"snowflake"}],"bookingTrustItems":[{"icon":"check-circle","title":"Operador local autorizado","description":"Operador turístico coreano certificado con seguro completo","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Especialistas en rutas","description":"Itinerario diseñado a medida, no un circuito genérico","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Grupos de tamaño seleccionado","description":"Dimensionado adecuadamente para la ruta","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"De inmediato","title":"Confirmación instantánea","detail":"Confirmación de reserva con resumen del itinerario"},{"timing":"12 horas antes","title":"Recordatorio de 12 horas","detail":"Actualización meteorológica y posibles ajustes en la ruta"},{"timing":"La tarde anterior","title":"**Información final de recogida**","detail":"Hora exacta de recogida y contacto del conductor"},{"timing":"La mañana del tour","title":"","detail":"Briefing matutino basado en las condiciones en tiempo real"},{"timing":"Durante el tour","title":"**Consejos parada a parada**","detail":"Orientación en tiempo real en cada lugar"},{"timing":"Después del tour","title":"**Soporte post-tour**","detail":"Seguimiento y recomendaciones"}],"staticQuestions":[{"id":"q1","question":"¿En qué se diferencia este tour del de Suwon + Pueblo Folclórico o Suwon + Cueva de Gwangmyeong?","answer":"Los tres comparten la Fortaleza Hwaseong de Suwon + el Palacio Hwaseong Haenggung + la Biblioteca Starfield. Esta versión añade el Templo Waujeongsa en Yongin (budista, más de 3.000 estatuas, el Buda reclinado de madera más grande del mundo). La versión del Pueblo Folclórico añade el Pueblo Folclórico Coreano (más de 270 casas tradicionales, escenario de rodaje de k-dramas). La versión de Gwangmyeong añade el parque subterráneo de cuevas iluminado con LEDs. Elija esta opción si la escultura budista es lo que más le interesa; la versión del Pueblo Folclórico para una experiencia más profunda del patrimonio; Gwangmyeong para variedad y actividades en interior sin depender del clima."},{"id":"q2","question":"¿Están incluidas las entradas?","answer":"Sí — las tres atracciones de pago están incluidas: Fortaleza Hwaseong de Suwon (1.000 KRW adulto), Palacio Hwaseong Haenggung (1.500 KRW adulto) y Templo Waujeongsa (entrada gratuita). La Biblioteca Starfield también es gratuita para todos. Las consumiciones opcionales en cafeterías, las comidas en el patio de comidas del centro comercial y cualquier compra de souvenirs corren por cuenta del visitante."},{"id":"q3","question":"¿Está incluido el almuerzo?","answer":"No. El almuerzo es durante el tiempo libre en el patio de comidas del centro comercial Starfield Suwon — amplia variedad, ambiente informal, aproximadamente entre 10.000 y 20.000 KRW por persona. La biblioteca y el centro comercial son la parada n.º 2 (llegada aproximada a las 13:30), por lo que el horario funciona como un descanso natural entre Hwaseong por la mañana y Waujeongsa por la tarde."},{"id":"q4","question":"¿Qué hace especial al Templo Waujeongsa?","answer":"Es un templo no tradicional: fundado en 1970 por el monje Kim Hae-Geun (un refugiado norcoreano) y construido en torno a la colección personal de su fundador, con más de 3.000 estatuas de Buda provenientes de toda Asia. Las piezas estrella son el Buldu — una cabeza de Buda en madera de 8 metros registrada en el Libro Guinness de los Récords como la más grande del mundo — y el Wabul, un Buda reclinado de madera de 3 m × 12 m tallado en enebro indonesio. La Campana de la Unificación, de 12 toneladas, fue tocada en la inauguración de los Juegos Olímpicos de Seúl 1988. Entrada gratuita; se recomiendan ≈75 minutos."},{"id":"q5","question":"¿Es necesario vestir con modestia para visitar el templo?","answer":"Se recomienda llevar los hombros cubiertos en Waujeongsa — lleve una capa ligera si usa camiseta sin mangas en verano. Los sombreros se retiran habitualmente al entrar en las salas principales. No existe un código de vestimenta estricto para los terrenos exteriores del templo, pero la ropa discreta es apreciada como muestra de respeto. Se recomiendan calzado cómodo con agarre para las escaleras e inclinaciones del templo."},{"id":"q6","question":"¿Cómo se distribuye el esfuerzo físico a lo largo del día?","answer":"Tres estilos de caminata diferenciados: la muralla de la Fortaleza Hwaseong tiene la sección más exigente (pendientes pronunciadas, escaleras en las puertas, ≈1 km recorrido); la Biblioteca Starfield es completamente interior con escaleras mecánicas; Waujeongsa tiene escaleras e inclinaciones en los terrenos del templo (nivel moderado). Caminata total de ≈3-4 km a lo largo del día. Calzado cómodo imprescindible, especialmente para el recorrido por la muralla y los senderos del templo."},{"id":"first-time","question":"¿Es una buena opción para quienes visitan Suwon y Yongin por primera vez?","answer":"Sí — esta es una de las mejores opciones para viajeros que desean visitar en un solo día guiado un sitio Patrimonio de la UNESCO, un espacio fotográfico contemporáneo y un templo budista singular. El formato mantiene un equilibrio entre lo activo y lo contemplativo, con las paradas geográficamente próximas (corredor Suwon-Yongin, a ≈30 minutos entre sí). El servicio gratuito de recogida en hotel desde Hongdae o Myeongdong simplifica la logística matutina."},{"id":"walking","question":"¿Es difícil caminar?","answer":"Caminata activa moderada. La sección más exigente es la Fortaleza Hwaseong: ≈1 km de recorrido por muralla de piedra con pendientes pronunciadas, escaleras en las puertas y superficies históricas irregulares — se requieren calzado cómodo con buena tracción. La Biblioteca Starfield es una caminata fácil en interiores sobre pisos planos. El Templo Waujeongsa tiene algunos senderos cuesta arriba y escaleras (moderado). Caminata total ≈3-4 km a lo largo del día. Los cochecitos de bebé son difíciles en la muralla y en el templo, pero se pueden usar sin problema en Starfield."},{"id":"family","question":"¿Este tour es adecuado para familias?","answer":"Sí — cómodo para la mayoría de las familias con niños a partir de 6 años. Los cochecitos de bebé son difíciles en la muralla de Hwaseong y en Waujeongsa, pero Starfield es totalmente accesible con escaleras mecánicas y ascensores. Los niños suelen responder con entusiasmo a la enorme cabeza del Buda de Waujeongsa y a la colección de más de 3.000 estatuas. El alquiler de hanbok en el Palacio Hwaseong Haenggung es un momento fotográfico muy popular para familias (y ofrece entrada gratuita a la fortaleza)."},{"id":"seniors","question":"¿Pueden participar adultos mayores cómodamente?","answer":"Sí, para personas mayores activas que se sientan cómodas con escaleras y terreno irregular; más limitado para viajeros con movilidad reducida. El recorrido por la muralla de Hwaseong tiene las secciones más exigentes (pendientes pronunciadas, escalones de piedra); los adultos mayores pueden recorrer los tramos planos más sencillos y omitir el ascenso a los puestos de mando. Waujeongsa tiene escaleras en los terrenos del templo, pero la colección principal de estatuas se encuentra en niveles accesibles. Starfield cuenta con acceso completo mediante escaleras mecánicas y ascensores — la parada de recuperación."},{"id":"children","question":"¿Cuál es la edad mínima recomendada?","answer":"Lo más adecuado es a partir de los 6 años aproximadamente. La muralla de la fortaleza tiene escaleras y superficies históricas irregulares, y los terrenos del templo Waujeongsa tienen pendientes que cansan a los niños muy pequeños. Los niños mayores lo disfrutan bien — la enorme cabeza del Buda y la Campana de la Unificación generan un gran impacto visual, y la biblioteca de Starfield es accesible. Los cochecitos de bebé funcionan bien en Starfield, pero no en la muralla."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id se resuelve en tiempo de ejecución desde Supabase / env; no forma parte del JSONB estático.","price":{"amountLabel":"","currency":"USD","per":"person","salePriceUsd":null,"originalPriceUsd":null,"discountPercent":null}},"pickup_dropoff":{"departure":[{"order":1,"time":"08:30","name":"Estación Hongik Univ. (Salida 4)","type":"station","note":"Primer punto de encuentro en Seúl; por favor llegue con 10 minutos de antelación.","lat":37.55753,"lng":126.92447},{"order":2,"time":"09:00","name":"Estación Myeongdong","type":"station","note":"Segundo punto de encuentro en Seúl.","lat":37.56099,"lng":126.98619}],"return":[{"order":1,"name":"Estación Myeongdong","type":"station","note":"Punto estándar de llegada en Seúl.","lat":37.56099,"lng":126.98619},{"order":2,"name":"Estación Hongik Univ.","type":"station","note":"Punto estándar de llegada en Seúl.","lat":37.55753,"lng":126.92447}],"notes":["La hora de regreso depende del tráfico y suele estar entre las 18:00 y las 19:00. El orden de llegada puede ajustarse ligeramente por eficiencia operativa. Por favor llegue al menos 10 minutos antes a su punto de encuentro seleccionado. Este tour tiene puntos de encuentro fijos, no incluye recogida en hotel."]},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"seoul-suwon-hwaseong-waujeongsa-starfield","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"gyeonggi_south","vehicle_type":"minicoach","duration_hours":9,"region_tags":["seoul_capital","gyeonggi_suwon","gyeonggi_yongin","gyeonggi_south","seoul_day_trip"],"theme_tags":["unesco","fortress","buddhist_temple","contemporary_architecture","k_drama_filming_location","first_time_friendly","iconic_landmarks","heritage_plus_modern"],"poi_tags":["hwaseong_fortress","hwaseong_haenggung","starfield_library_suwon","waujeongsa_temple","yeonhwasan"],"pace_level":0.6,"walking_level":0.6,"scenic_leve